async def list_days(update: Update, context: ContextTypes.DEFAULT_TYPE):
    days = get_existing_days(1, 99)
    if not days:
        await update.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… Щ…ШӯЩҒЩҲШёШ©.")
        return

    locked = load_locked_days()
    lines = ["рҹ“… Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ЩҲШ¬ЩҲШҜШ©:"]
    for day in days:
        rows = read_day_rows(day)
        participants = sum(1 for r in rows if r["participated"])
        scored = any(r["total"] > 0 for r in rows)
        lock = "рҹ”’" if str(day) in locked else "рҹ”“"
        calc = "Щ…ШӯШіЩҲШЁ" if scored else "ШЁШҜЩҲЩҶ ЩҶШӘШ§ШҰШ¬"
        lines.append(f"Ш§Щ„ЩҠЩҲЩ… {day} {lock} вҖ” {participants} Щ…ШҙШ§ШұЩғ вҖ” {calc}")
    await update.message.reply_text("\n".join(lines))


async def inspect_day(update: Update, context: ContextTypes.DEFAULT_TYPE):
    day = get_day(update.message.text)
    rows = read_day_rows(day)
    if not rows:
        await update.message.reply_text(f"Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„ЩҒ Ш§Щ„ЩҠЩҲЩ… {day}.")
        return

    participants = [r for r in rows if r["participated"]]
    max_score = max([r["total"] for r in rows], default=0)
    winners = [r["participant"] for r in rows if r["total"] == max_score and max_score > 0]
    zeros = [r["participant"] for r in participants if r["total"] == 0]
    avg = round(sum(r["total"] for r in rows) / len(rows), 2) if rows else 0
    locked = "Щ…ЩӮЩҒЩ„ рҹ”’" if is_locked(day) else "Щ…ЩҒШӘЩҲШӯ рҹ”“"

    lines = [
        f"рҹ”Һ ЩҒШӯШө Ш§Щ„ЩҠЩҲЩ… {day}",
        f"Ш§Щ„ШӯШ§Щ„Ш©: {locked}",
        f"Ш№ШҜШҜ Ш§Щ„Щ…ШҙШ§ШұЩғЩҠЩҶ: {len(participants)}",
        f"ШЈШ№Щ„Щү ЩҶЩӮШ§Ш·: {max_score}",
        f"ШЈШіШ·ЩҲШұШ© Ш§Щ„ЩҠЩҲЩ…: {'ШҢ '.join(winners) if winners else 'Щ„Ш§ ЩҠЩҲШ¬ШҜ'}",
        f"Ш№ШҜШҜ Ш§Щ„Щ„ЩҠ Ш¬Ш§ШЁЩҲШ§ 0: {len(zeros)}",
        f"Щ…ШӘЩҲШіШ· Ш§Щ„ЩҶЩӮШ§Ш·: {avg}",
    ]
    if zeros:
        lines.append("\nШ§Щ„ШЈШөЩҒШ§Шұ:")
        lines.extend([f"- {name}" for name in zeros])
    await update.message.reply_text("\n".join(lines))


async def participants_day(update: Update, context: ContextTypes.DEFAULT_TYPE):
    day = get_day(update.message.text)
    rows = read_day_rows(day)
    if not rows:
        await update.message.reply_text(f"Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„ЩҒ Ш§Щ„ЩҠЩҲЩ… {day}.")
        return

    yes = [r["participant"] for r in rows if r["participated"]]
    no = [r["participant"] for r in rows if not r["participated"]]
    lines = [f"рҹ‘Ҙ Щ…ШҙШ§ШұЩғЩҲ Ш§Щ„ЩҠЩҲЩ… {day}:"]
    lines.extend([f"вң… {name}" for name in yes] or ["Щ„Ш§ ЩҠЩҲШ¬ШҜ"])
    lines.append("\nЩ„Щ… ЩҠШҙШ§ШұЩғ:")
    lines.extend([f"вқҢ {name}" for name in no] or ["Щ„Ш§ ЩҠЩҲШ¬ШҜ"])
    await update.message.reply_text("\n".join(lines))


