# ============================================================
import random

MATCHUPS_FILE = "matchups_history.json"
CUP_FILE = "fantasy_cup_history.json"


def font_candidates():
    """Ш®Ш·ЩҲШ· Ш№ШұШЁЩҠШ© Щ…ШұШӘШЁШ© ШЁШ§Щ„ШЈЩҲЩ„ЩҲЩҠШ©: Ш№ЩҶЩҲШ§ЩҶ Ш«Щ… ЩҶШөШҢ ЩҠШ®ШӘШ§Шұ ШЈЩҲЩ„ Ш§Щ„Щ…ЩҲШ¬ЩҲШҜ."""
    return [
        "Tajawal-Black.ttf",
        "Tajawal-ExtraBold.ttf",
        "Cairo-Bold.ttf",
        "Cairo-Bold-1.ttf",
        "NotoNaskhArabic-Bold.ttf",
        "Amiri-Bold.ttf",
        "NotoNaskhArabic-Regular.ttf",
        "/app/Tajawal-Black.ttf",
        "/app/Tajawal-ExtraBold.ttf",
        "/app/Cairo-Bold.ttf",
        "/app/Cairo-Bold-1.ttf",
        "/app/NotoNaskhArabic-Bold.ttf",
        "/app/Amiri-Bold.ttf",
        "/usr/share/fonts/truetype/noto/NotoNaskhArabic-Bold.ttf",
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
    ]


def load_json_file(path, default):
    if not os.path.exists(path):
        return default
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if data is not None else default
    except Exception:
        return default


def save_json_file(path, data):
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def active_participants_for_day(day):
    return [r for r in read_day_rows(day) if r.get("participated")]


def daily_score_map(day):
    rows = read_day_rows(day)
    return {r["participant"]: r["total"] for r in rows}


def previous_ranking_before_day(day):
    try:
        d = int(day)
    except Exception:
        d = 1
    if d <= 1:
        return {name: i for i, name in enumerate(PARTICIPANTS, start=1)}
    stats = collect_stats(1, d - 1)
    if not stats["days"]:
        return {name: i for i, name in enumerate(PARTICIPANTS, start=1)}
    return {name: i for i, name in enumerate(stats["ranking"], start=1)}


def generate_matchups_for_day(day, force=False):
    """Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„ЩҠЩҲЩ… ШӘШёЩҮШұ ШЁШ№ШҜ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҒЩӮШ·. ЩҠШҜШ®Щ„ ЩҒЩӮШ· Ш§Щ„Щ…ШҙШ§ШұЩғЩҲЩҶ ЩҒШ№Щ„ЩҠЩӢШ§ ЩҒЩҠ Ш°Щ„Щғ Ш§Щ„ЩҠЩҲЩ…."""
    day_key = str(day)
    history = load_json_file(MATCHUPS_FILE, {})
    if (not force) and day_key in history:
        return history[day_key]

    active = [r["participant"] for r in active_participants_for_day(day)]
    if not active:
        result = {"day": day_key, "pairs": [], "bye": None, "note": "Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШҙШ§ШұЩғЩҲЩҶ"}
        history[day_key] = result
        save_json_file(MATCHUPS_FILE, history)
        return result

    # ЩӮШұШ№Ш© Ш«Ш§ШЁШӘШ© ШӯШіШЁ Ш§Щ„ЩҠЩҲЩ…ШҢ ШәЩҠШұ Щ…ШұШӘШЁШ·Ш© ШЁШ§Щ„ЩҶЩӮШ§Ш·.
    names = sorted(active)
    rnd = random.Random(int(day) * 2026 + 77)
    rnd.shuffle(names)

    bye = None
    if len(names) % 2 == 1:
        bye = names.pop()

    pairs = []
    scores = daily_score_map(day)
    for i in range(0, len(names), 2):
        a, b = names[i], names[i + 1]
        pa, pb = scores.get(a, 0), scores.get(b, 0)
        if pa > pb:
            winner, status = a, "ЩҒЩҲШІ"
        elif pb > pa:
            winner, status = b, "ЩҒЩҲШІ"
        else:
            # ЩҒЩҠ Ш§Щ„ШӘШ№Ш§ШҜЩ„ ЩҠЩҒЩҲШІ Ш§Щ„ШЈШ№Щ„Щү ШӘШұШӘЩҠШЁЩӢШ§ ЩӮШЁЩ„ Ш§Щ„Ш¬ЩҲЩ„Ш©
            ranks = previous_ranking_before_day(day)
            winner = a if ranks.get(a, 999) <= ranks.get(b, 999) else b
            status = "ШӘШ№Ш§ШҜЩ„ вҖ” ШӯЩҸШіЩ… ШЁШ§Щ„ШЈЩҒШ¶Щ„ЩҠШ©"
        pairs.append({"a": a, "a_points": pa, "b": b, "b_points": pb, "winner": winner, "status": status})

    result = {"day": day_key, "pairs": pairs, "bye": bye, "note": ""}
    history[day_key] = result
    save_json_file(MATCHUPS_FILE, history)
    return result


def matchup_lines(day):
    data = generate_matchups_for_day(day)
    if not data.get("pairs") and not data.get("bye"):
        return ["вҡ”пёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„ЩҠЩҲЩ…:", "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ вҖ” Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШҙШ§ШұЩғЩҲЩҶ ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ…."]
    lines = [f"вҡ”пёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}"]
    for p in data.get("pairs", []):
        mark = "рҹӨқ" if "ШӘШ№Ш§ШҜЩ„" in p.get("status", "") else "вң…"
        lines.append(f"{p['a']} {p['a_points']} - {p['b_points']} {p['b']} {mark} Ш§Щ„ЩҒШ§ШҰШІ: {p['winner']}")
    if data.get("bye"):
        lines.append(f"рҹҹЎ ШұШ§ШӯШ© Ш§Щ„Ш¬ЩҲЩ„Ш©: {data['bye']}")
    return lines


def matchup_wins_map(start_day=1, end_day=31):
    wins = Counter()
    for day in get_existing_days(start_day, end_day):
        data = generate_matchups_for_day(day)
        for p in data.get("pairs", []):
            if p.get("winner"):
                wins[p["winner"]] += 1
        if data.get("bye"):
            # Ш§Щ„ШұШ§ШӯШ© Щ„Ш§ ШӘШӯШӘШіШЁ ЩҒЩҲШІЩӢШ§.
            pass
    return wins


def add_matchups_sheet_to_dashboard(xlsx_path, start_day=1, end_day=31):
    wb = load_workbook(xlsx_path)
    if "ШіШ¬Щ„ Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ" in wb.sheetnames:
        del wb["ШіШ¬Щ„ Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ"]
    ws = wb.create_sheet("ШіШ¬Щ„ Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ")
    ws.sheet_view.rightToLeft = True
    ws.append(["Ш§Щ„ЩҠЩҲЩ…", "Ш§Щ„Щ…ШҙШ§ШұЩғ 1", "ЩҶЩӮШ§Ш·ЩҮ", "Ш§Щ„Щ…ШҙШ§ШұЩғ 2", "ЩҶЩӮШ§Ш·ЩҮ", "Ш§Щ„ЩҶШӘЩҠШ¬Ш©", "Ш§Щ„ЩҒШ§ШҰШІ"])
    for day in get_existing_days(start_day, end_day):
        data = generate_matchups_for_day(day)
        if not data.get("pairs") and not data.get("bye"):
            ws.append([day, "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ", "", "Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШҙШ§ШұЩғЩҲЩҶ", "", "-", "-"])
            continue
        for p in data.get("pairs", []):
            ws.append([day, p["a"], p["a_points"], p["b"], p["b_points"], p.get("status", ""), p.get("winner", "")])
        if data.get("bye"):
            ws.append([day, data["bye"], "ШұШ§ШӯШ©", "-", "-", "ШұШ§ШӯШ© Ш§Щ„Ш¬ЩҲЩ„Ш©", data["bye"]])
    style_sheet(ws)
    wb.save(xlsx_path)


def build_daily_summary_text(day):
    data = build_day_summary(day)
    winners = " ЩҲ ".join(data["winners"]) if data["winners"] else "Щ„Ш§ ЩҠЩҲШ¬ШҜ"
    top_rows = data["sorted_rows"][:5]
    lines = [
        f"рҹ“Ҡ Щ…Щ„Ш®Шө Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}",
        f"рҹ‘Ҙ Ш№ШҜШҜ Ш§Щ„Щ…ШҙШ§ШұЩғЩҠЩҶ: {len(data['participants'])}",
        f"рҹҸҶ ШЈШіШ·ЩҲШұШ© Ш§Щ„ЩҠЩҲЩ…: {winners} вҖ” {data['max_score']} ЩҶЩӮШ·Ш©",
        "",
        "рҹ”Ҙ ШЈЩҒШ¶Щ„ 5:",
    ]
    for idx, r in enumerate(top_rows, start=1):
        lines.append(f"{idx}. {r['participant']} вҖ” {r['total']} ЩҶЩӮШ·Ш©")
    top_cap = data.get("top_captain")
    top_keep = data.get("top_keeper")
    if top_cap:
        lines.append(f"\nрҹ‘‘ ШЈЩҒШ¶Щ„ ЩғШ§ШЁШӘЩҶ: {top_cap['participant']} вҖ” +{top_cap['captain_points']}")
    if top_keep:
        lines.append(f"рҹ§Ө ШЈЩҒШ¶Щ„ ШӯШ§ШұШі: {top_keep['participant']} вҖ” +{top_keep['keeper_points']}")
    lines.append("")
    lines.extend(matchup_lines(day))
    return "\n".join(lines)


