        rounded_rect(draw, (90,y,width-90,y+row_h), radius=36, fill=c+"D5", outline="#FFFFFF30", width=2)
        cy = y + row_h//2
        paste_flag(img, a, (width-280, cy-55, width-105, cy+55))
        paste_flag(img, b, (105, cy-55, 280, cy+55))
