async def fixtures_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return

    await q.answer()

    if not is_admin_user(update):
        await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return

    parts = (q.data or "").split("|")
    action = parts[1] if len(parts) > 1 else ""

    try:
        if action == "menu":
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲ Ш§ШіШӘШ®ШҜЩ… /Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06", reply_markup=_fixtures_dates_keyboard("single"))
            return

        if action == "multi":
            context.user_data["fx_selected_dates"] = []
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш¶ШәШ· Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…ЩҶШ§ШіШЁ:", reply_markup=_fixtures_dates_keyboard("multi", []))
            return

        if action == "toggle" and len(parts) >= 3:
            d = parts[2]
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if d in sel:
                sel.remove(d)
            else:
                sel.append(d)
            context.user_data["fx_selected_dates"] = sel
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш¶ШәШ· Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…ЩҶШ§ШіШЁ:", reply_markup=_fixtures_dates_keyboard("multi", sel))
            return

        if action == "clear":
            context.user_data["fx_selected_dates"] = []
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш¶ШәШ· Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…ЩҶШ§ШіШЁ:", reply_markup=_fixtures_dates_keyboard("multi", []))
            return

        if action == "day" and len(parts) >= 3:
            d = parts[2]
            await q.message.edit_text(_fixtures_day_text(d), reply_markup=_fixtures_day_keyboard(d))
            return

        if action in ["render1", "render2"] and len(parts) >= 3:
            d = parts[2]
            design = 1 if action == "render1" else 2
            wait = await q.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
            try:
                paths = _render_fixture_day_by_design(d, design=design)
                if not paths:
                    await wait.edit_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ….")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(q.message, p, _fixtures_caption(_v25_fixture_title(d)))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ЩҠЩҲЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        if action == "render_each":
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if not sel:
                await q.message.reply_text("Ш§Ш®ШӘШұ ЩҠЩҲЩ…ЩӢШ§ ЩҲШ§ШӯШҜЩӢШ§ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
                return
            wait = await q.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШЈЩҠШ§Щ…...")
            try:
                try:
                    await wait.delete()
                except Exception:
                    pass
                for d in sel:
                    for p in _render_fixture_day_by_design(d, design=2):
                        await send_photo_path(q.message, p, _fixtures_caption(_v25_fixture_title(d)))
            except Exception as e:
                await q.message.reply_text(f"ШӘШ№Ш°Шұ Ш§Щ„ШӘШөЩ…ЩҠЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        if action == "render_combo":
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if not sel:
                await q.message.reply_text("Ш§Ш®ШӘШұ ЩҠЩҲЩ…ЩӢШ§ ЩҲШ§ШӯШҜЩӢШ§ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
                return
            wait = await q.message.reply_text("вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…Ш¬Щ…Ш№...")
            try:
                paths = render_fixtures_combined_images(sel)
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(q.message, p, _fixtures_caption("Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…Ш¬Щ…Ш№Ш©"))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…Ш¬Щ…Ш№ вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        if action == "upd" and len(parts) >= 3:
            mid = parts[2]
            m = _fixture_by_id(mid)
            if not m:
                await q.message.reply_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©.")
                return

            context.user_data["fixture_update_match_id"] = mid
            await q.message.reply_text(
                f"Ш§ЩғШӘШЁ Ш·ШұЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„ЩҖ {mid} ({m.get('date')} {m.get('time')}) ЩғШ°Ш§:\n"
                "Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„ * Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„Ш«Ш§ЩҶЩҠ\n\n"
                "Щ…Ш«Ш§Щ„: Ш§Щ„Щ…ЩғШіЩҠЩғ * ШЈШіШӘШұШ§Щ„ЩҠШ§\n"
                "Щ…Щ„Ш§ШӯШёШ©: ШіЩҠШӘЩ… Ш§Щ„ШӯЩҒШё ЩҒЩӮШ·ШҢ ЩҲЩ„ЩҶ ЩҠШӘЩ… Ш§Щ„ШӘШөЩ…ЩҠЩ… ШҘЩ„Ш§ Ш№ЩҶШҜЩ…Ш§ ШӘШ·Щ„ШЁ /Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӘШ§ШұЩҠШ®."
            )
            return

        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
    except Exception as e:
        await q.message.reply_text(f"ШӘШ№Ш°Шұ ШӘЩҶЩҒЩҠШ° Ш®ЩҠШ§Шұ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ вқҢ\n{str(e)[:400]}")


async def fixtures_update_text_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    mid = context.user_data.get("fixture_update_match_id")
    if not mid:
        return

    text = (update.message.text or "").strip()

    if "*" in text:
        a, b = [x.strip() for x in text.split("*", 1)]
    elif "Г—" in text:
        a, b = [x.strip() for x in text.split("Г—", 1)]
    elif "-" in text:
        a, b = [x.strip() for x in text.split("-", 1)]
    else:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§: Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„ * Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„Ш«Ш§ЩҶЩҠ")
        return

    if not a or not b:
        await update.message.reply_text("Ш§ЩғШӘШЁ Ш§ШіЩ… Ш§Щ„ЩҒШұЩҠЩӮЩҠЩҶ ЩғШ§Щ…Щ„ЩҠЩҶ.")
        return

    data = _load_fixture_updates()
    data.setdefault(mid, {})
    data[mid]["team1"] = canonical_team_name(a) or normalize_name(a)
    data[mid]["team2"] = canonical_team_name(b) or normalize_name(b)
    _save_fixture_updates(data)

    context.user_data.pop("fixture_update_match_id", None)

    m = _apply_fixture_updates(_fixture_by_id(mid) or {"id": mid})
    await update.message.reply_text(
        f"вң… ШӘЩ… ШӯЩҒШё ШӘШӯШҜЩҠШ« Ш§Щ„Щ…ШЁШ§ШұШ§Ш©\n"
        f"{m.get('team1')} Г— {m.get('team2')} вҖ” {m.get('time', '')}\n\n"
        f"Щ„ЩҶ ШЈШөЩ…Щ… Ш§Щ„ШўЩҶ. ЩҲЩӮШӘ Щ…Ш§ ШӘШЁЩҠЩҮШ§ Ш§ЩғШӘШЁ:\n/Щ…ШЁШ§ШұЩҠШ§ШӘ {m.get('date', '')}"
    )

# ==================== END V25 FIXTURES DESIGN OVERRIDE ====================


async def api_check_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    lines = ["ЩҒШӯШө Щ…ШөШ§ШҜШұ Ш§Щ„ЩҶШӘШ§ШҰШ¬:", ""]
    # SerpApi
    if _serpapi_key():
        try:
            data = serpapi_search_json("Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ЩғШіЩҠЩғ ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©", timeout=8)
            lines.append("вң… SERPAPI_KEY Щ…ЩҲШ¬ЩҲШҜ ЩҲШ§Щ„Ш§ШӘШөШ§Щ„ ШЁЩӮЩҲЩӮЩ„ ШҙШәШ§Щ„")
            if isinstance(data.get("sports_results"), dict):
                lines.append("вң… Google Sports ШёЩҮШұ ЩҒЩҠ ЩҶШӘЩҠШ¬Ш© Ш§Щ„ЩҒШӯШө")
            else:
                lines.append("вҡ пёҸ Ш§Щ„Ш§ШӘШөШ§Щ„ ШҙШәШ§Щ„ШҢ Щ„ЩғЩҶ Щ„Щ… ЩҠШёЩҮШұ ЩғШұШӘ Google Sports ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ЩҒШӯШө")
        except Exception as e:
            lines.append(f"вқҢ SerpApi Щ…ЩҲШ¬ЩҲШҜ Щ„ЩғЩҶ ЩҒШҙЩ„ Ш§Щ„Ш§ШӘШөШ§Щ„: {str(e)[:120]}")
    else:
        lines.append("вқҢ SERPAPI_KEY ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ")
    # API-Football
    if _api_football_key():
        try:
            _api_football_get("/status", {})
            lines.append("вң… API_FOOTBALL_KEY Щ…ЩҲШ¬ЩҲШҜ ЩҲШ§Щ„Ш§ШӘШөШ§Щ„ ШҙШәШ§Щ„")
            lid = get_api_football_league_id()
            if lid:
                lines.append(f"вң… League ID Ш§Щ„ШӯШ§Щ„ЩҠ Щ„ЩғШЈШі Ш§Щ„Ш№Ш§Щ„Щ…: {lid}")
            else:
                lines.append("вҡ пёҸ Щ„Щ… ЩҠШӘЩ… ШӘШӯШҜЩҠШҜ League ID ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§")
        except Exception as e:
            lines.append(f"вқҢ API-Football ЩҒШҙЩ„: {str(e)[:120]}")
    else:
        lines.append("вқҢ API_FOOTBALL_KEY ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ")
    await update.message.reply_text("\n".join(lines))


async def google_search_debug_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = parse_command_body_lines(update.message.text)
    q = " ".join(body).strip() or "Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ЩғШіЩҠЩғ ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©"
    msg = await update.message.reply_text(f"вҸі ШЈЩҒШӯШө ЩӮЩҲЩӮЩ„: {q}")
    try:
        data = serpapi_search_json(q, timeout=8)
        sr = data.get("sports_results") if isinstance(data, dict) else None
        lines = ["ЩҶШӘЩҠШ¬Ш© ЩҒШӯШө ЩӮЩҲЩӮЩ„:", f"query: {q}"]
        if isinstance(sr, dict):
            lines.append("вң… sports_results Щ…ЩҲШ¬ЩҲШҜ")
            # Try list visible team names
            names = []
            for node in _walk_json(sr):
                if isinstance(node, dict):
                    nm = _team_name_from_any(node)
                    if nm and nm not in names:
                        names.append(nm)
                    if len(names) >= 6:
                        break
            if names:
                lines.append("ЩҒШұЩӮ/ШЈШіЩ…Ш§ШЎ ШёЩҮШұШӘ: " + "ШҢ ".join(names[:6]))
            lines.append("Щ…ЩҒШ§ШӘЩҠШӯ: " + "ШҢ ".join(list(sr.keys())[:12]))
        else:
            lines.append("вҡ пёҸ Щ„Щ… ЩҠШёЩҮШұ sports_results")
        await msg.edit_text("\n".join(lines))
    except Exception as e:
        await msg.edit_text(f"вқҢ ЩҒШҙЩ„ ЩҒШӯШө ЩӮЩҲЩӮЩ„: {str(e)[:180]}")


async def current_groups_now_command(update: Update, context: ContextTypes.DEFAULT_TYPE, mode_override=None):
    text = update.message.text if getattr(update, 'message', None) else ""
    mode = mode_override
    if not mode:
        m = re.search(r"\*\s*(ШұШіЩ…ЩҠ|ШіШұЩҠШ№|Ш§Щ„ШЈШӯШҜШ«|Ш§Щ„Ш§ШӯШҜШ«|official|fast|latest)\s*$", text or "", re.I)
        mode = m.group(1) if m else "official"
    payload = {"kind": "standings"}
    kb = source_keyboard(context, payload)
    msg = await update.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ ЩҒШӯШө ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)}...")
    groups, source_label = fetch_current_groups(mode)
    if not groups:
        await msg.edit_text(_source_help_text("standings", mode), reply_markup=kb)
        return
    path = create_all_groups_image(groups)
    await msg.delete()
    await send_photo_path_markup(update.message, path, f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң…\nШ§Щ„Щ…ШөШҜШұ Ш§Щ„ШӯШ§Щ„ЩҠ: {mode_label_ar(mode)} ({source_label})", kb)
    await update.message.reply_text(build_groups_text(groups, f"{mode_label_ar(mode)} ({source_label})"))


async def live_match_command(update: Update, context: ContextTypes.DEFAULT_TYPE, mode_override=None):
    team1, team2, mode, date_hint = parse_live_command_text(update.message.text if getattr(update, 'message', None) else "")
    if mode_override:
        mode = mode_override
    if not team1 or not team2:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/Щ…ШЁШ§ШҙШұ Ш§Щ„ШіШ№ЩҲШҜЩҠШ© * Ш§ШіШЁШ§ЩҶЩҠШ§\nШЈЩҲ\n/Щ…ШЁШ§ШҙШұ Ш§Щ„ШіШ№ЩҲШҜЩҠШ© * Ш§ШіШЁШ§ЩҶЩҠШ§ * ШіШұЩҠШ№\nШЈЩҲ ШЁШӘШ§ШұЩҠШ® Щ…ШӯШҜШҜ:\n/Щ…ШЁШ§ШҙШұ Ш§Щ„Щ…ЩғШіЩҠЩғ * ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ© * 18/06/2026 * ШіШұЩҠШ№")
        return
    payload = {"kind": "live", "team1": team1, "team2": team2, "date_hint": date_hint}
    kb = source_keyboard(context, payload)
    wait = await update.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШЁШӯШ« Ш№ЩҶ {team1} Г— {team2} Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)}...")
    data = fetch_live_match_data(team1, team2, mode, date_hint=date_hint)
    if not data:
        await wait.edit_text(
            f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n"
            f"Щ…ШЁШ§ШұШ§Ш©: {team1} Г— {team2}\n" + (f"Ш§Щ„ШӘШ§ШұЩҠШ®: {date_hint}\n" if date_hint else "") +
            "\nШ¬ШұЩ‘ШЁ ШІШұ Ш§Щ„ШЈШӯШҜШ« ШЈЩҲ Ш§ЩғШӘШЁ Ш§Щ„ШӘШ§ШұЩҠШ®.\n"
            "ЩҲЩ„Щ„ШӘШҙШ®ЩҠШө Ш§ШіШӘШ®ШҜЩ…: /ШЁШӯШ«_ЩӮЩҲЩӮЩ„ Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ЩғШіЩҠЩғ ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©",
            reply_markup=kb,
        )
        return
    path = render_live_match_card(data, mode_label_ar(mode))
    try:
        await wait.delete()
    except Exception:
        pass
    await send_photo_path_markup(update.message, path, build_live_caption(data, mode_label_ar(mode)), kb)


async def sports_source_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return
    await query.answer()
    if not is_admin_user(update):
        await query.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return
    parts = (query.data or "").split("|")
    if len(parts) != 3:
        await query.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
        return
    _tag, token, mode = parts
    payload = context.bot_data.get("sports_source_requests", {}).get(token)
    if not payload:
        await query.message.reply_text("Ш§ЩҶШӘЩҮШӘ ШөЩ„Ш§ШӯЩҠШ© Ш§Щ„Ш®ЩҠШ§ШұШҢ ШЈШ№ШҜ ШӘЩҶЩҒЩҠШ° Ш§Щ„ШЈЩ…Шұ Щ…ЩҶ Ш¬ШҜЩҠШҜ.")
        return
    kind = payload.get("kind")
    kb = source_keyboard(context, payload)
    if kind == "standings":
        msg = await query.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ ЩҒШӯШө ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)}...")
        groups, src = fetch_current_groups(mode)
        if not groups:
            await msg.edit_text(_source_help_text("standings", mode), reply_markup=kb)
            return
        path = create_all_groups_image(groups)
        try:
            await msg.delete()
        except Exception:
            pass
        await send_photo_path_markup(query.message, path, f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң…\nШ§Щ„Щ…ШөШҜШұ Ш§Щ„ШӯШ§Щ„ЩҠ: {mode_label_ar(mode)} ({src})", kb)
        await query.message.reply_text(build_groups_text(groups, f"{mode_label_ar(mode)} ({src})"))
        return
    if kind == "live":
        team1, team2 = payload.get("team1"), payload.get("team2")
        msg = await query.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШЁШӯШ« Ш№ЩҶ {team1} Г— {team2} Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)}...")
        data = fetch_live_match_data(team1, team2, mode, date_hint=payload.get("date_hint"))
        if not data:
            await msg.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2} Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=kb)
            return
        path = render_live_match_card(data, mode_label_ar(mode))
        try:
            await msg.delete()
        except Exception:
            pass
        await send_photo_path_markup(query.message, path, build_live_caption(data, mode_label_ar(mode)), kb)
        return
    await query.message.reply_text("ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШҜ ЩҶЩҲШ№ Ш§Щ„Ш·Щ„ШЁ.")

