def main():
    if not TOKEN:
        raise RuntimeError("Ш¶Ш№ ШӘЩҲЩғЩҶ Ш§Щ„ШЁЩҲШӘ ЩҒЩҠ Щ…ШӘШәЩҠШұ Ш§Щ„ШЁЩҠШҰШ© BOT_TOKEN")
    ensure_flags_assets()
    ensure_design_assets()
    load_participants_state()
    app = ApplicationBuilder().token(TOKEN).build()

    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"(?i)^/start(?:@\w+)?(?:\s|$)"), start))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/(?:Щ…ЩҶ_Ш§ЩҶШ§|Щ…Ш№ШұЩҒЩҠ)"), who_am_i))
    app.add_handler(MessageHandler(filters.Document.ALL, remember_last_file))

    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШӘЩҒШ№ЩҠЩ„_Ш§Щ„ШөЩҲШұ_Ш§Щ„ШӘЩ„ЩӮШ§ШҰЩҠШ©"), admin_only(enable_auto_images)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШҘЩҠЩӮШ§ЩҒ_Ш§Щ„ШөЩҲШұ_Ш§Щ„ШӘЩ„ЩӮШ§ШҰЩҠШ©"), admin_only(disable_auto_images)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§ЩҠЩӮШ§ЩҒ_Ш§Щ„ШөЩҲШұ_Ш§Щ„ШӘЩ„ЩӮШ§ШҰЩҠШ©"), admin_only(disable_auto_images)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШөЩҲШұШ©_Ш§Щ„ЩҠЩҲЩ…"), daily_image_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШөЩҲШұШ©_Ш§Щ„ШӘШұШӘЩҠШЁ"), overall_image_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШөЩҲШұШ©_Ш§Щ„Ш§ШіШ§Ш·ЩҠШұ"), legends_image_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШөЩҲШұШ©_Ш§ШӯШөШ§ШҰЩҠШ§ШӘ"), dashboard_sheet_image_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШөЩҲШұ_Ш§Щ„Ш§ШӯШөШ§ШҰЩҠШ§ШӘ"), all_dashboard_images_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Щ…Щ„ЩҒ_Ш§Щ„Ш§ШӯШөШ§ШҰЩҠШ§ШӘ(?:\s|$)"), statistics_pdf_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШЁШ·Ш§ЩӮШ©"), participant_card_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШӘЩӮШұЩҠШұ_Ш§Щ„ЩҒШӘШұШ©"), period_report_command))

    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§Ш№Щ„Ш§ЩҶ_Ш§Щ„ЩҠЩҲЩ…"), announcement_day_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Щ…Щ„Ш®Шө_Ш§Щ„ЩҠЩҲЩ…"), summary_day_command))
    # V23 ШЈЩҲШ§Щ…Шұ Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„ШҘШ¶Ш§ЩҒЩҠ
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШӘШөЩ…ЩҠЩ…_Щ…ШЁШ§ШұЩҠШ§ШӘ_ШіШӘШ§ЩҠЩ„2(?:\s|$)"), admin_only(design_matches_style2_command)))
