    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШҘШ№Ш§ШҜШ©_Ш§Щ„ЩғШ§Ші_Щ…ЩҶ(?:\s|$)"), admin_only(reset_cup_from_day_command)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§Ш№Ш§ШҜШ©_Ш§Щ„ЩғШ§Ші_Щ…ЩҶ(?:\s|$)"), admin_only(reset_cup_from_day_command)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§Щ„ШәШ§ШЎ_Ш§Щ„ЩғШ§Ші(?:\s|$)"), admin_only(cancel_cup_command)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШҘЩ„ШәШ§ШЎ_Ш§Щ„ЩғШ§Ші(?:\s|$)"), admin_only(cancel_cup_command)))

    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§Ш¶Ш§ЩҒЩҮ(?:\s|$)"), admin_only(add_day)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§Ш№ШӘЩ…Ш§ШҜ_ЩҶШӘШ§ШҰШ¬(?:\s|$)"), admin_only(approve_results_day)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/(?:ЩҶШӘШ§ШҰШ¬_Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ|ЩҶШӘШ§ЩҠШ¬_Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ)(?:\s|$)"), previous_results_command))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШӘШӯШҜЩҠШ«_ЩҶШӘШ§ШҰШ¬(?:\s|$)"), admin_only(refresh_results_command)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ЩҶШӘШ§ШҰШ¬(?:\s|$)"), admin_only(results_day)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§Щ„ШӘШұШӘЩҠШЁ_Ш§Щ„Ш№Ш§Щ…"), overall))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ШӘШұШӘЩҠШЁ_ЩҶШө"), ranking_text))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/?(?:Ш§ШӯШөШ§ШҰЩҠШ§ШӘ|ШҘШӯШөШ§ШҰЩҠШ§ШӘ)(?:\s|$)"), dashboard))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/(Ш§Щ„ШЈЩҠШ§Щ…|Ш§Щ„Ш§ЩҠШ§Щ…)"), list_days))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/ЩҒШӯШө(?:\\s|$)"), inspect_day))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Щ…ШҙШ§ШұЩғЩҠЩҶ"), participants_day))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Ш§ШіШ·ЩҲШұШ©"), legend_day))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Щ…ЩӮШ§ШұЩҶШ©"), compare_days))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Щ…ШіШӯ_Ш§Щ„ЩғЩ„"), admin_only(clear_all)))
    app.add_handler(MessageHandler(filters.TEXT & filters.Regex(r"^/Щ…ШіШӯ_ЩҠЩҲЩ…"), admin_only(clear_day)))
