    draw_text(draw, (width//2, height-108), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(32), fill="#FDE68A")
