async def qualified_add_many_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = parse_command_body_lines(update.message.text)
    if not body:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/Щ…ШӘШЈЩҮЩ„ЩҠЩҶ\nШ§Щ„Щ…ЩғШіЩҠЩғ\nШ§Щ„ЩҠШ§ШЁШ§ЩҶ\nЩҒШұЩҶШіШ§")
        return
    if len(body) == 1 and ("," in body[0] or "ШҢ" in body[0]):
        names = [normalize_name(x) for x in re.split(r"[,ШҢ]", body[0]) if normalize_name(x)]
    else:
        names = body
    teams = load_qualified32_state()
    added, invalid, skipped = [], [], []
    for raw in names:
        team = canonical_team_name(raw)
        if not team:
            invalid.append(raw)
            continue
        if team in teams or team in added:
            skipped.append(team)
            continue
        if len(teams) + len(added) >= 32:
            break
        added.append(team)
    teams.extend(added)
    save_qualified32_state(teams)
    path = render_qualified32_board(teams)
    cap = [f"ШӘЩ… ШӘШӯШҜЩҠШ« Щ„ЩҲШӯШ© Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ вң…\nШ§Щ„Щ…Ш¬Щ…ЩҲШ№ Ш§Щ„ШӯШ§Щ„ЩҠ: {len(teams)}/32"]
    if added:
        cap.append("\nШӘЩ…ШӘ Ш§Щ„ШҘШ¶Ш§ЩҒШ©:\n- " + "\n- ".join(added))
    if skipped:
        cap.append("\nЩ…ЩҲШ¬ЩҲШҜ Щ…ШіШЁЩӮЩӢШ§:\n- " + "\n- ".join(skipped[:8]))
    if invalid:
        cap.append("\nШӘШ№Ш°Шұ Ш§Щ„ШӘШ№ШұЩҒ Ш№Щ„Щү:\n- " + "\n- ".join(invalid[:8]))
    await send_photo_path(update, path, "\n".join(cap))


