async def current_groups_now_command(update: Update, context: ContextTypes.DEFAULT_TYPE, mode_override=None):
    text = update.message.text if getattr(update, 'message', None) else ""
    mode = mode_override
    if not mode:
        m = re.search(r"\*\s*(ШұШіЩ…ЩҠ|ШіШұЩҠШ№|Ш§Щ„ШЈШӯШҜШ«|official|fast|latest)\s*$", text or "", re.I)
        mode = m.group(1) if m else "official"
    payload = {"kind": "standings"}
    kb = source_keyboard(context, payload)
    try:
        groups, source_label = fetch_current_groups(mode)
        if not groups:
            await update.message.reply_text("ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ Ш§Щ„Щ…ШөШҜШұ Ш§Щ„ШӯШ§Щ„ЩҠ.\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=kb)
            return
        path = create_all_groups_image(groups)
        caption = f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң…\nШ§Щ„Щ…ШөШҜШұ Ш§Щ„ШӯШ§Щ„ЩҠ: {mode_label_ar(mode)}"
        await send_photo_path_markup(update.message, path, caption, kb)
        await update.message.reply_text(build_groups_text(groups, mode_label_ar(mode)))
    except Exception:
        await update.message.reply_text(
            f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:",
            reply_markup=kb,
        )

