def team_query_name(team):
    team = canonical_team_name(team) or normalize_name(team)
    arr = TEAM_SEARCH_EN.get(team) or [team]
    return arr[0]


def team_query_names(team):
    team = canonical_team_name(team) or normalize_name(team)
    return [team] + (TEAM_SEARCH_EN.get(team) or [])


def _as_int(v, default=0):
    try:
        if v is None or v == "":
            return default
        if isinstance(v, str):
            v = re.sub(r"[^0-9\-]", "", v)
            if v in ("", "-"):
                return default
        return int(float(v))
    except Exception:
        return default


def _norm_status_ar(status, short=None, elapsed=None):
    raw = normalize_name(status or short or "")
    low = raw.lower()
    if short in ("FT", "AET", "PEN") or any(x in low for x in ["final", "full", "Ш§ЩҶШӘЩҮ", "ЩҶЩҮШ§ЩҠШ©"]):
        return "Ш§ЩҶШӘЩҮШӘ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©"
    if short in ("NS", "TBD") or any(x in low for x in ["not started", "scheduled", "Щ„Щ… ШӘШЁШҜШЈ"]):
        return "Щ„Щ… ШӘШЁШҜШЈ"
    if short in ("1H", "2H", "LIVE", "HT", "ET", "BT") or any(x in low for x in ["live", "half", "Щ…ШЁШ§ШҙШұ"]):
        if elapsed:
            return f"Щ…ШЁШ§ШҙШұ вҖ” {elapsed}'"
        return "Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ"
    return raw or (f"{elapsed}'" if elapsed else "ШәЩҠШұ Щ…ШӯШҜШҜ")


def _safe_get(d, *keys, default=None):
    cur = d
    for k in keys:
        if isinstance(cur, dict):
            cur = cur.get(k)
        else:
            return default
    return default if cur is None else cur


def _crop_alpha_content(img):
    try:
        if img.mode != "RGBA":
            img = img.convert("RGBA")
        alpha = img.getchannel("A")
        bbox = alpha.getbbox()
        if bbox:
            return img.crop(bbox)
    except Exception:
        pass
    return img.convert("RGBA")


def _rounded_mask(w, h, radius=8):
    mask = Image.new("L", (max(1, w), max(1, h)), 0)
    md = ImageDraw.Draw(mask)
    try:
        md.rounded_rectangle((0, 0, w-1, h-1), radius=radius, fill=255)
    except Exception:
        md.rectangle((0, 0, w, h), fill=255)
    return mask


def _paste_flag_stretched(base, team_name, box, radius=8):
    """Щ„ЩҲШӯШ© Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ ЩҒЩӮШ·: Ш№Щ„Щ… Ш№Ш§Щ…ЩҲШҜЩҠ ЩҠЩ…Щ„ШЈ Ш§Щ„Ш¬ШІШЎ Ш§Щ„ШЈШЁЩҠШ¶ШҢ ШЁШҜЩҲЩҶ Ш®Щ„ЩҒЩҠШ© ШіЩҲШҜШ§ШЎ ШЈЩҲ ШҙЩҒШ§ЩҒЩҠШ©."""
    path = flag_path_for(team_name)
    x1, y1, x2, y2 = [int(v) for v in box]
    w, h = max(1, x2-x1), max(1, y2-y1)
    d = ImageDraw.Draw(base)
    # Ш®Щ„ЩҒЩҠШ© ШЁЩҠШ¶Ш§ШЎ ШҜШ§ШҰЩ…Ш§ЩӢ ШӯШӘЩү Щ„Ш§ ШӘШёЩҮШұ Щ…ШұШЁШ№Ш§ШӘ ШіЩҲШҜШ§ШЎ Щ…ЩҶ PNG Ш§Щ„ШҙЩҒШ§ЩҒ
    try:
        rounded_rect(d, (x1, y1, x2, y2), radius=radius, fill="#FFFFFF", outline="#E5E7EB", width=1)
    except Exception:
        d.rectangle((x1, y1, x2, y2), fill="#FFFFFF")
    if path and os.path.exists(path):
        try:
            flag = Image.open(path).convert("RGBA")
            flag = _crop_alpha_content(flag)
            # Ш§Щ„Щ…Ш·Щ„ЩҲШЁ ЩҮЩҶШ§ Ш№Ш§Щ…ЩҲШҜЩҠ: ЩҶЩ…ШҜШҜ Ш§Щ„Ш№Щ„Щ… Ш№Щ„Щү ЩғШ§Щ…Щ„ Ш§Щ„Щ…ШұШЁШ№ Ш§Щ„ШЈШЁЩҠШ¶ШҢ Щ…Ш«Щ„ Щ…Ш«Ш§Щ„ Ш§Щ„Щ…ЩғШіЩҠЩғ.
            flag = flag.resize((w, h), Image.LANCZOS)
            canvas = Image.new("RGBA", (w, h), (255, 255, 255, 255))
            canvas.paste(flag, (0, 0), flag if flag.mode == "RGBA" else None)
            mask = _rounded_mask(w, h, radius)
            base.paste(canvas.convert("RGB"), (x1, y1), mask)
            return
        except Exception:
            pass
    draw_text(d, ((x1+x2)//2, (y1+y2)//2), (normalize_name(team_name) or "?")[:2], get_font(22), fill="#061633")


def render_qualified32_board(teams):
    """Щ„ЩҲШӯШ© Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ Ш§Щ„ШұШіЩ…ЩҠШ©: PNG Ш«Ш§ШЁШӘ + ШЁШҜШ§ЩҠШ© Щ…ЩҶ ШЈШ№Щ„Щү Ш§Щ„ЩҠЩ…ЩҠЩҶ + Ш№Щ„Щ… Ш№Ш§Щ…ЩҲШҜЩҠ."""
    ensure_generated_dir()
    tpl = _qualified32_template_path()
    if tpl:
        img = Image.open(tpl).convert("RGB")
        # Ш§Щ„ЩӮШ§Щ„ШЁ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ 1086Г—1448ШҢ ЩҲЩ„ЩҲ Ш§Ш®ШӘЩ„ЩҒ ЩҶШӯШ§ЩҒШё Ш№Щ„Щү ЩҶЩҒШі Ш§Щ„ЩҶШіШЁШ©.
        if img.size != (1086, 1448):
            img = img.resize((1086, 1448), Image.LANCZOS)
    else:
        width, height = 1086, 1448
        img = Image.new("RGB", (width, height), "#F8FAFC")
        d = ImageDraw.Draw(img)
        draw_text(d, (width//2, 180), "ЩғШЈШі Ш§Щ„Ш№Ш§Щ„Щ… 2026", get_font(62), fill="#061633")
        draw_text(d, (width//2, 238), "Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„Щ…ШӘШЈЩҮЩ„Ш© ШҘЩ„Щү ШҜЩҲШұ Ш§Щ„ЩҖ 32", get_font(34), fill="#061633")
        for r in range(4):
            for c in range(8):
                x = 31 + c*130
                y = 531 + r*198
                rounded_rect(d, (x, y, x+112, y+182), radius=13, fill="#FFFFFF", outline="#94A3B8", width=2)
                rounded_rect(d, (x, y+145, x+112, y+182), radius=10, fill="#061633")
    draw = ImageDraw.Draw(img)
    # ШҘШӯШҜШ§Ш«ЩҠШ§ШӘ Ш§Щ„ЩӮШ§Щ„ШЁ Ш§Щ„Щ…Ш№ШӘЩ…ШҜШҢ Щ…ШұШӘШЁШ© ШЁШөШұЩҠЩӢШ§ Щ…ЩҶ Ш§Щ„ЩҠШіШ§ШұШҢ ЩҲШіЩҶЩӮЩ„ШЁЩҮШ§ Щ„Щ„ШЁШҜШЎ Щ…ЩҶ Ш§Щ„ЩҠЩ…ЩҠЩҶ.
    x_ranges = [(31,142), (159,270), (287,400), (417,531), (547,661), (679,792), (809,922), (939,1053)]
    white_tops = [531, 729, 926, 1123]
    footer_starts = [677, 875, 1072, 1269]
    footer_h = 37
    order = []
    for r in range(4):
        for x1, x2 in reversed(x_ranges):
            order.append((x1, x2, white_tops[r], footer_starts[r]))
    for idx, team in enumerate((teams or [])[:32]):
        x1, x2, yt, yf = order[idx]
        # Ш§Щ„Ш¬ШІШЎ Ш§Щ„ШЈШЁЩҠШ¶ ЩҒЩӮШ·ШҢ ЩҲЩҠШӘШұЩғ Ш§Щ„ШҙШұЩҠШ· Ш§Щ„ШЈШІШұЩӮ Щ„Щ„Ш§ШіЩ….
        flag_box = (x1+3, yt+5, x2-3, yf-3)
