async def api_check_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    lines = ["ЩҒШӯШө Щ…ШөШ§ШҜШұ Ш§Щ„ЩҶШӘШ§ШҰШ¬:", ""]
    # SerpApi
    if _serpapi_key():
        try:
            data = serpapi_search_json("Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ЩғШіЩҠЩғ ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©")
            lines.append("вң… SERPAPI_KEY Щ…ЩҲШ¬ЩҲШҜ ЩҲШ§Щ„Ш§ШӘШөШ§Щ„ ШЁЩӮЩҲЩӮЩ„ ШҙШәШ§Щ„")
            if isinstance(data.get("sports_results"), dict):
                lines.append("вң… Google Sports ШёЩҮШұ ЩҒЩҠ ЩҶШӘЩҠШ¬Ш© Ш§Щ„ЩҒШӯШө")
            else:
                lines.append("вҡ пёҸ Ш§Щ„Ш§ШӘШөШ§Щ„ ШҙШәШ§Щ„ШҢ Щ„ЩғЩҶ Щ„Щ… ЩҠШёЩҮШұ ЩғШұШӘ Google Sports ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ЩҒШӯШө")
        except Exception as e:
            lines.append(f"вқҢ SerpApi Щ…ЩҲШ¬ЩҲШҜ Щ„ЩғЩҶ ЩҒШҙЩ„ Ш§Щ„Ш§ШӘШөШ§Щ„: {str(e)[:120]}")
    else:
        lines.append("вқҢ SERPAPI_KEY ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ")
    # API-Football
    if _api_football_key():
        try:
            status = _api_football_get("/status", {})
            lines.append("вң… API_FOOTBALL_KEY Щ…ЩҲШ¬ЩҲШҜ ЩҲШ§Щ„Ш§ШӘШөШ§Щ„ ШҙШәШ§Щ„")
            lid = get_api_football_league_id()
            if lid:
                lines.append(f"вң… League ID Ш§Щ„ШӯШ§Щ„ЩҠ Щ„ЩғШЈШі Ш§Щ„Ш№Ш§Щ„Щ…: {lid}")
            else:
                lines.append("вҡ пёҸ Щ„Щ… ЩҠШӘЩ… ШӘШӯШҜЩҠШҜ League ID ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§")
        except Exception as e:
            lines.append(f"вқҢ API-Football ЩҒШҙЩ„: {str(e)[:120]}")
    else:
        lines.append("вқҢ API_FOOTBALL_KEY ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ")
    await update.message.reply_text("\n".join(lines))


