async def google_search_debug_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = parse_command_body_lines(update.message.text)
    query = " ".join(body).strip() or "Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ЩғШіЩҠЩғ ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©"
    msg = await update.message.reply_text(f"вҸі ШЈЩҒШӯШө ЩӮЩҲЩӮЩ„: {query}")
    try:
        data = await _asyncio_v6.wait_for(_asyncio_v6.to_thread(serpapi_search_json, query, "ar", "sa", 8), timeout=12)
        sr = data.get("sports_results") if isinstance(data, dict) else None
        lines = ["ЩҶШӘЩҠШ¬Ш© ЩҒШӯШө ЩӮЩҲЩӮЩ„:", f"query: {query}"]
        if isinstance(sr, dict):
            lines.append("вң… sports_results Щ…ЩҲШ¬ЩҲШҜ")
            lines.append("Щ…ЩҒШ§ШӘЩҠШӯ: " + "ШҢ ".join(list(sr.keys())[:12]))
            # Try parse the requested/known Mexico-Korea match if present.
            obj = None
            for root in [sr, data]:
                obj = _parse_serp_sports_node_v6(root, "Ш§Щ„Щ…ЩғШіЩҠЩғ", "ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©", source_name="Google Sports")
                if obj:
                    break
            if obj:
                lines.append(f"вң… ЩӮШұШЈШӘ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©: {obj['team1']} {obj['score1']} - {obj['score2']} {obj['team2']}")
                lines.append(f"Ш§Щ„ШӯШ§Щ„Ш©: {obj.get('status','')}")
            else:
                names = []
                for node in _walk_json(sr):
                    if isinstance(node, dict):
                        nm = _team_name_from_any_v6(node)
                        if nm and nm not in names:
                            names.append(nm)
                    if len(names) >= 8:
                        break
                if names:
                    lines.append("ШЈШіЩ…Ш§ШЎ ШёЩҮШұШӘ: " + "ШҢ ".join(names[:8]))
                lines.append("вҡ пёҸ ЩҲШөЩ„ЩҶШ§ Щ„ЩӮЩҲЩӮЩ„ Щ„ЩғЩҶ Щ„Щ… ШЈЩӮШұШЈ Ш§Щ„ЩҶШӘЩҠШ¬Ш© Щ…ЩҶ Ш§Щ„ШЁЩҶЩҠШ© Ш§Щ„ШӯШ§Щ„ЩҠШ©")
        else:
            lines.append("вҡ пёҸ Щ„Щ… ЩҠШёЩҮШұ sports_results")
        await msg.edit_text("\n".join(lines[:12]))
    except Exception as e:
        await msg.edit_text(f"вқҢ ЩҒШҙЩ„ ЩҒШӯШө ЩӮЩҲЩӮЩ„: {str(e)[:220]}")

# ==================== END V6 HOTFIX ====================


