    draw_text(draw, (width//2, 160), "LIVE MATCH", _v31_latin_font(74), fill="#FFFFFF", max_width=900)
    draw_text(draw, (width//2, 222), "Щ…ШӘШ§ШЁШ№Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш©", get_font(34), fill="#FDE68A", max_width=720)

