def _fixtures_dates_keyboard(mode="single", selected=None):
    selected = set(selected or [])
    rows = []
    row = []

    for d, day in _fixture_dates():
        label = f"{'вң… ' if d in selected else ''}{day} {d[:5]}"
        data = f"fx|toggle|{d}" if mode == "multi" else f"fx|day|{d}"
        row.append(InlineKeyboardButton(label, callback_data=data))
        if len(row) == 2:
            rows.append(row)
            row = []

    if row:
        rows.append(row)

    if mode == "multi":
        rows.append([
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… Ш¬ШҜЩҠШҜ", callback_data="fx|render_combo_new"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="fx|render_combo_10"),
        ])
        rows.append([
            InlineKeyboardButton("ШӘШөЩҒЩҠШұ Ш§Щ„Ш§Ш®ШӘЩҠШ§Шұ", callback_data="fx|clear"),
            InlineKeyboardButton("ШұШ¬ЩҲШ№", callback_data="fx|menu"),
        ])
    else:
        rows.append([InlineKeyboardButton("Ш§Ш®ШӘЩҠШ§Шұ ШЈЩғШ«Шұ Щ…ЩҶ ЩҠЩҲЩ…", callback_data="fx|multi")])

    return InlineKeyboardMarkup(rows)


def _fixtures_day_text(date):
    rows, matches = _v26_fixture_simple_matches(date)
    if not matches:
        return "Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ШӘШ§ШұЩҠШ®."

    lines = [f"{_v26_fixture_title(date)}", ""]
    for i, m in enumerate(rows, 1):
        lines.append(f"{i}) {_v26_safe_txt(m.get('team1'))} Г— {_v26_safe_txt(m.get('team2'))} вҖ” {_v26_short_time(m.get('time'))}")
        extra = []
        if m.get("stage"):
            extra.append(_v26_safe_txt(m.get("stage")))
        if m.get("group"):
            extra.append(_v26_safe_txt(m.get("group")))
        if extra:
            lines.append("   " + " | ".join(extra))
        if _has_unknown(m) and m.get("note"):
            lines.append(f"   {_v26_safe_txt(m.get('note'))}")

    return "\n".join(lines)


def _v26_combo_choice_keyboard():
    return InlineKeyboardMarkup([
        [
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… Ш¬ШҜЩҠШҜ", callback_data="fx|render_combo_new"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="fx|render_combo_10"),
        ]
    ])


async def fixtures_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text or ""
    dates = _extract_fixture_dates_from_text(text)

    if dates:
        if len(dates) == 1:
            d = dates[0]
            wait = await update.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
            try:
                rows, simple = _v26_fixture_simple_matches(d)
                paths = _render_fixture_day_by_design(d, design=2)
                if not paths:
                    await wait.edit_text(f"Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ ШЁШӘШ§ШұЩҠШ® {d}")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(update.message, p, _v26_fixtures_caption(_v26_fixture_title(d), simple, include_fantasy=True))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ЩҠЩҲЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        # ШЈЩғШ«Шұ Щ…ЩҶ ШӘШ§ШұЩҠШ®: Щ„Ш§ ЩҠШөЩ…Щ… Щ…ШЁШ§ШҙШұШ©ШҢ ЩҠШ№Ш·ЩҠ ШІШұЩҠЩҶ
        clean_dates = []
        for d in dates:
            if d not in clean_dates:
                clean_dates.append(d)
        context.user_data["fx_selected_dates"] = clean_dates
        await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ… Щ„Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӯШҜШҜШ©:", reply_markup=_v26_combo_choice_keyboard())
        return

    await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲ Ш§ЩғШӘШЁ:\n/Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06", reply_markup=_fixtures_dates_keyboard("single"))


