async def live_match_command(update: Update, context: ContextTypes.DEFAULT_TYPE, mode_override=None):
    team1, team2, mode, date_hint = parse_live_command_text(update.message.text)
    if mode_override:
        mode = _norm_source_mode(mode_override)

    # /Щ…ШЁШ§ШҙШұ ШЁШҜЩҲЩҶ Щ…ШЁШ§ШұШ§Ш© = ШЈШІШұШ§Шұ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ЩҶШҙШ·
    if not team1 or not team2:
        d = _v29_active_fixture_date()
        if not d:
            await update.message.reply_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Щ…Щ„ЩҒ PDF.")
            return
        await update.message.reply_text(_v29_live_today_text(d), reply_markup=_v29_live_today_keyboard(d))
        return

    payload = {"kind": "live", "team1": team1, "team2": team2, "date_hint": date_hint}
    kb = source_keyboard(context, payload)
    wait = await update.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШЁШӯШ« Ш№ЩҶ Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}\nШ§Щ„Щ…ШөШҜШұ: {mode_label_ar(mode)}")
    try:
        data = await asyncio.wait_for(asyncio.to_thread(fetch_live_match_data, team1, team2, mode, date_hint), timeout=26)
    except Exception as e:
        data = None
    if not data:
        await wait.edit_text(
            f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n"
            f"Щ…ШЁШ§ШұШ§Ш©: {team1} Г— {team2}\n"
            "Ш¬ШұШЁ Щ…ШөШҜШұ Ш«Ш§ЩҶЩҠ Щ…ЩҶ Ш§Щ„ШЈШІШұШ§Шұ.",
            reply_markup=kb,
        )
        return
    try:
        path = render_live_match_card(data, mode_label_ar(mode))
        await send_photo_path_markup(update.message, path, build_live_caption(data, mode_label_ar(mode)), kb)
        try:
            await wait.delete()
        except Exception:
            pass
    except Exception as e:
        await wait.edit_text(f"ШӘЩ… Ш¬Щ„ШЁ Ш§Щ„ЩҶШӘЩҠШ¬Ш© Щ„ЩғЩҶ ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШөЩҲШұШ© вқҢ\n{str(e)[:180]}\n\n" + build_live_caption(data, mode_label_ar(mode)), reply_markup=kb)


async def live_today_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    if len(parts) < 3:
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Ш®ШӘЩҠШ§Шұ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©.")
        return
    action, mid = parts[1], parts[2]
    if action != "match":
        return
    m = _fixture_by_id(mid)
    if not m:
        await q.message.reply_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ЩҒЩҠ Щ…Щ„ЩҒ PDF.")
        return
    if _has_unknown(m):
        await q.message.reply_text("ШЈШ·ШұШ§ЩҒ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„Щ… ШӘШӘШӯШҜШҜ ШЁШ№ШҜ.")
        return
    team1, team2 = m.get("team1"), m.get("team2")
    date_hint = _v28_espn_date(m.get("date")) if '_v28_espn_date' in globals() else m.get("date")
    payload = {"kind": "live", "team1": team1, "team2": team2, "date_hint": date_hint}
    kb = source_keyboard(context, payload)
    wait = await q.message.reply_text(f"вҸі ШЈШ¬ЩҮШІ ШЁШ·Ш§ЩӮШ© {team1} Г— {team2} Щ…ЩҶ ESPN...")
    try:
        data = await asyncio.wait_for(asyncio.to_thread(fetch_live_match_data, team1, team2, "espn", date_hint), timeout=26)
    except Exception:
        data = None
    if not data:
        await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ ESPN вқҢ\n{team1} Г— {team2}", reply_markup=kb)
        return
    try:
        path = render_live_match_card(data, "ESPN")
        await send_photo_path_markup(q.message, path, build_live_caption(data, "ESPN"), kb)
        try:
            await wait.delete()
        except Exception:
            pass
    except Exception as e:
        await wait.edit_text(f"ШӘЩ… Ш¬Щ„ШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Щ„ЩғЩҶ ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШЁШ·Ш§ЩӮШ© вқҢ\n{str(e)[:180]}\n\n" + build_live_caption(data, "ESPN"), reply_markup=kb)


