async def sports_source_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    ШЈШІШұШ§Шұ Щ…ШөШ§ШҜШұ Ш§Щ„ШұЩҠШ§Ш¶Ш© ШЈШөШЁШӯШӘ Ш№Ш§Щ…Ш© Щ„Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ Щ„ШЈЩҶЩҮШ§ ШӘШ®Шө /Щ…ШЁШ§ШҙШұ ЩҲ/ШӘШұШӘЩҠШЁ.
    """
    query = update.callback_query
    if not query:
        return
    await query.answer()
    parts = (query.data or "").split("|")
    if len(parts) != 3:
        await query.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
        return
    _tag, token, mode = parts
    payload = context.bot_data.get("sports_source_requests", {}).get(token)
    if not payload:
        await query.message.reply_text("Ш§ЩҶШӘЩҮШӘ ШөЩ„Ш§ШӯЩҠШ© Ш§Щ„Ш®ЩҠШ§ШұШҢ ШЈШ№ШҜ ШӘЩҶЩҒЩҠШ° Ш§Щ„ШЈЩ…Шұ Щ…ЩҶ Ш¬ШҜЩҠШҜ.")
        return
    kind = payload.get("kind")
    kb = source_keyboard(context, payload)

    if kind == "standings":
        msg = await query.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ {mode_label_ar(mode)}...")
        try:
            groups, src = await asyncio.wait_for(asyncio.to_thread(fetch_current_groups, mode), timeout=32)
        except Exception:
            groups, src = [], ""
        if not groups:
            await msg.edit_text(_source_help_text("standings", mode), reply_markup=kb)
            return
        path = create_all_groups_newlook_image(groups)
        try:
            await msg.delete()
        except Exception:
            pass
        await send_photo_path_markup(query.message, path, f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң…\nШ§Щ„Щ…ШөШҜШұ: {src}", kb)
        return

    if kind == "live":
        team1 = payload.get("team1")
        team2 = payload.get("team2")
        date_hint = payload.get("date_hint")
        msg = await query.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШЁШӯШ« Ш№ЩҶ Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}\nШ§Щ„Щ…ШөШҜШұ: {mode_label_ar(mode)}")
        try:
            data = await asyncio.wait_for(asyncio.to_thread(fetch_live_match_data, team1, team2, mode, date_hint), timeout=26)
        except Exception:
            data = None
        if not data:
            await msg.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\nЩ…ШЁШ§ШұШ§Ш©: {team1} Г— {team2}", reply_markup=kb)
            return
        try:
            path = render_live_match_card(data, mode_label_ar(mode))
            await send_photo_path_markup(query.message, path, build_live_caption(data, mode_label_ar(mode)), kb)
            try:
                await msg.delete()
            except Exception:
                pass
        except Exception as e:
            await msg.edit_text(f"ШӘЩ… Ш¬Щ„ШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Щ„ЩғЩҶ ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШЁШ·Ш§ЩӮШ© вқҢ\n{str(e)[:180]}\n\n" + build_live_caption(data, mode_label_ar(mode)), reply_markup=kb)
        return

    await query.message.reply_text("ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШҜ ЩҶЩҲШ№ Ш§Щ„Ш·Щ„ШЁ.")


async def fixtures_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    ШЈШІШұШ§Шұ /Щ…ШЁШ§ШұЩҠШ§ШӘ ШЈШөШЁШӯШӘ Ш№Ш§Щ…Ш© Щ„Щ„Ш№ШұШ¶ШҢ Щ„ЩғЩҶ ШӘШ№ШҜЩҠЩ„ ШЈШ·ШұШ§ЩҒ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҠШЁЩӮЩү Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ·.
    """
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    action = parts[1] if len(parts) > 1 else ""

    if _v29_is_admin_action(action) and not is_admin_user(update):
        await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return

    try:
        if action == "menu":
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲ Ш§ШіШӘШ®ШҜЩ… /Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06", reply_markup=_fixtures_dates_keyboard("single"))
            return
        if action == "multi":
            context.user_data["fx_selected_dates"] = []
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ…:", reply_markup=_fixtures_dates_keyboard("multi", []))
            return
        if action == "toggle" and len(parts) >= 3:
            d = parts[2]
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if d in sel:
                sel.remove(d)
            else:
                sel.append(d)
            context.user_data["fx_selected_dates"] = sel
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ…:", reply_markup=_fixtures_dates_keyboard("multi", sel))
            return
        if action == "clear":
            context.user_data["fx_selected_dates"] = []
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ…:", reply_markup=_fixtures_dates_keyboard("multi", []))
            return
        if action == "day" and len(parts) >= 3:
            d = parts[2]
            await q.message.edit_text(_fixtures_day_text(d), reply_markup=_fixtures_day_keyboard(d))
            return
        if action in ["render1", "render2"] and len(parts) >= 3:
            d = parts[2]
            design = 1 if action == "render1" else 2
            wait = await q.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
            try:
                rows, simple = _v26_fixture_simple_matches(d)
                paths = _render_fixture_day_by_design(d, design=design)
                if not paths:
                    await wait.edit_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ….")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(q.message, p, _v26_fixtures_caption(_v26_fixture_title(d), simple, include_fantasy=True))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ЩҠЩҲЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return
        if action in ["render_combo_new", "render_combo_10", "render_combo"]:
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if not sel:
                await q.message.reply_text("Ш§Ш®ШӘШұ ЩҠЩҲЩ…ЩӢШ§ ЩҲШ§ШӯШҜЩӢШ§ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
                return
            title = "Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Ш¬ШҜЩҠШҜ" if action != "render_combo_10" else "ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ"
            wait = await q.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… {title}...")
            try:
                paths = _v26_render_fixtures_10_images(sel) if action == "render_combo_10" else render_fixtures_combined_images(sel)
                if not paths:
                    await wait.edit_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„Щ„ШӘЩҲШ§ШұЩҠШ® Ш§Щ„Щ…ШӯШҜШҜШ©.")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(q.message, p, _v26_fixtures_caption("Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…Ш¬Щ…Ш№Ш©", [], include_fantasy=False))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ Ш§Щ„ШӘШөЩ…ЩҠЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return
        if action == "upd" and len(parts) >= 3:
            mid = parts[2]
            m = _fixture_by_id(mid)
            if not m:
                await q.message.reply_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©.")
                return
            context.user_data["fixture_update_match_id"] = mid
            await q.message.reply_text(
                f"Ш§ЩғШӘШЁ Ш·ШұЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„ЩҖ {mid} ({m.get('date')} {_v26_short_time(m.get('time'))}) ЩғШ°Ш§:\n"
                "Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„ * Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„Ш«Ш§ЩҶЩҠ\n\n"
                "Щ…Ш«Ш§Щ„: Ш§Щ„Щ…ЩғШіЩҠЩғ * ШЈШіШӘШұШ§Щ„ЩҠШ§\n"
                "Щ…Щ„Ш§ШӯШёШ©: ШіЩҠШӘЩ… Ш§Щ„ШӯЩҒШё ЩҒЩӮШ·ШҢ ЩҲЩ„ЩҶ ЩҠШӘЩ… Ш§Щ„ШӘШөЩ…ЩҠЩ… ШҘЩ„Ш§ Ш№ЩҶШҜЩ…Ш§ ШӘШ·Щ„ШЁ /Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӘШ§ШұЩҠШ®."
            )
            return
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
    except Exception as e:
        await q.message.reply_text(f"ШӘШ№Ш°Шұ ШӘЩҶЩҒЩҠШ° Ш®ЩҠШ§Шұ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ вқҢ\n{str(e)[:400]}")

# ==================== END V29 PUBLIC BOT + LIVE BUTTONS + GROUP MENU + ESPN TOP SCORERS ====================

# ==================== END V28 RESULTS + ESPN SCORERS + RTL STANDINGS ====================

# ==================== END V26 FINAL OVERRIDE ====================

# ==================== END V24 STABLE PATCH ====================



# ==================== V29+ PUBLIC MENU + QUALIFIED/ELIMINATED FINAL MERGE ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ: Ш§Щ„ЩӮШ§ШҰЩ…Ш© Щ„Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶШҢ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ЩҲШ§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ ШЁШӘШөЩ…ЩҠЩ… + ЩҶШөШҢ Щ…Ш№ ШҘШ¶Ш§ЩҒШ©/ШӯШ°ЩҒ ЩҠШҜЩҲЩҠ ЩҲШЈЩҲЩ„ЩҲЩҠШ© Щ„Щ„ЩҠШҜЩҲЩҠ.

STATUS_STATE_FILE = "qualification_status_state.json"
ELIMINATED_FILE = "eliminated_teams_state.json"


def _now_riyadh_text():
    try:
        return (datetime.utcnow() + timedelta(hours=3)).strftime("%Y-%m-%d %H:%M") + " ШЁШӘЩҲЩӮЩҠШӘ Щ…ЩғШ©"
    except Exception:
        return datetime.now().strftime("%Y-%m-%d %H:%M")


def _unique_teams(seq, limit=None):
    out = []
    for raw in seq or []:
        team = canonical_team_name(raw) or normalize_name(raw)
        if team and team not in out:
            out.append(team)
        if limit and len(out) >= limit:
            break
    return out


def _status_default_state():
    return {
        "qualified_auto": [],
        "qualified_manual_added": [],
        "qualified_manual_removed": [],
        "eliminated_auto": [],
        "eliminated_manual_added": [],
        "eliminated_manual_removed": [],
        "updated_at": "-",
        "source": "ЩҠШҜЩҲЩҠ",
    }


def load_status_state():
    state = _status_default_state()
    if os.path.exists(STATUS_STATE_FILE):
        try:
            with open(STATUS_STATE_FILE, "r", encoding="utf-8") as f:
                obj = json.load(f)
            if isinstance(obj, dict):
                state.update(obj)
        except Exception:
            pass
    # ШӘШұШӯЩҠЩ„ ШӘЩ„ЩӮШ§ШҰЩҠ Щ…ЩҶ Щ…Щ„ЩҒ V29 Ш§Щ„ЩӮШҜЩҠЩ… Щ„Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ ШҘЩҶ ЩҲШ¬ШҜ.
    if not state.get("qualified_manual_added") and os.path.exists(QUALIFIED32_FILE):
        try:
            with open(QUALIFIED32_FILE, "r", encoding="utf-8") as f:
                obj = json.load(f)
            teams = obj.get("teams", []) if isinstance(obj, dict) else []
            if teams:
                state["qualified_manual_added"] = _unique_teams(teams, 32)
        except Exception:
            pass
    # ШӘШұШӯЩҠЩ„ Щ…ЩҶ Щ…Щ„ЩҒ Щ…ШәШ§ШҜШұЩҠЩҶ ЩӮШҜЩҠЩ… ШҘЩҶ ЩҲШ¬ШҜ.
    if not state.get("eliminated_manual_added") and os.path.exists(ELIMINATED_FILE):
        try:
            with open(ELIMINATED_FILE, "r", encoding="utf-8") as f:
                obj = json.load(f)
            teams = obj.get("teams", []) if isinstance(obj, dict) else []
            if teams:
                state["eliminated_manual_added"] = _unique_teams(teams)
        except Exception:
            pass
    for key in ["qualified_auto", "qualified_manual_added", "qualified_manual_removed", "eliminated_auto", "eliminated_manual_added", "eliminated_manual_removed"]:
        state[key] = _unique_teams(state.get(key, []), 32 if key.startswith("qualified") else None)
    return state


def save_status_state(state):
    clean = _status_default_state()
    clean.update(state or {})
    for key in ["qualified_auto", "qualified_manual_added", "qualified_manual_removed", "eliminated_auto", "eliminated_manual_added", "eliminated_manual_removed"]:
        clean[key] = _unique_teams(clean.get(key, []), 32 if key.startswith("qualified") else None)
    with open(STATUS_STATE_FILE, "w", encoding="utf-8") as f:
        json.dump(clean, f, ensure_ascii=False, indent=2)
    # ЩҶШӯШ§ЩҒШё Ш№Щ„Щү Щ…Щ„ЩҒ V29 Ш§Щ„ЩӮШҜЩҠЩ… Ш№ШҙШ§ЩҶ ШЈЩҠ ШҜШ§Щ„Ш© ЩӮШҜЩҠЩ…Ш© Щ…Ш§ ШӘШӘШЈШ«Шұ.
    try:
        with open(QUALIFIED32_FILE, "w", encoding="utf-8") as f:
            json.dump({"teams": _status_effective_teams("qualified", clean)}, f, ensure_ascii=False, indent=2)
    except Exception:
        pass
    try:
        with open(ELIMINATED_FILE, "w", encoding="utf-8") as f:
            json.dump({"teams": _status_effective_teams("eliminated", clean)}, f, ensure_ascii=False, indent=2)
    except Exception:
        pass


def _status_effective_teams(kind="qualified", state=None):
    state = state or load_status_state()
    prefix = "qualified" if kind == "qualified" else "eliminated"
    manual = _unique_teams(state.get(f"{prefix}_manual_added", []))
    auto = _unique_teams(state.get(f"{prefix}_auto", []))
    removed = set(_unique_teams(state.get(f"{prefix}_manual_removed", [])))
    teams = []
    # Ш§Щ„ЩҠШҜЩҲЩҠ ШЈЩҲЩ„Ш§ЩӢ ЩҲЩ„ЩҮ ШЈЩҲЩ„ЩҲЩҠШ© ЩҒЩҠ Ш§Щ„ШӘШұШӘЩҠШЁ.
    for team in manual + auto:
        if team and team not in removed and team not in teams:
            teams.append(team)
    return teams[:32] if kind == "qualified" else teams


# ШҘШ№Ш§ШҜШ© ШӘШ№ШұЩҠЩҒ ШҜЩҲШ§Щ„ V29 Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШЁШӯЩҠШ« ШӘШіШӘШ№Щ…Щ„ Ш§Щ„ШӯШ§Щ„Ш© Ш§Щ„Ш¬ШҜЩҠШҜШ© ШЁШҜЩҲЩҶ ЩғШіШұ ШЈЩҲШ§Щ…Шұ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ.
def load_qualified32_state():
    return _status_effective_teams("qualified")


def save_qualified32_state(teams):
    state = load_status_state()
    state["qualified_manual_added"] = _unique_teams(teams, 32)
    state["updated_at"] = _now_riyadh_text()
    state["source"] = "ШӘШ№ШҜЩҠЩ„ ЩҠШҜЩҲЩҠ Щ…ЩҶ Ш§Щ„ШҘШҜШ§ШұШ©"
    save_status_state(state)


def _status_caption(kind, teams, state=None):
    state = state or load_status_state()
    if kind == "qualified":
        title = "вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§ ШҘЩ„Щү ШҜЩҲШұ 32 ШӯШӘЩү Ш§Щ„ШўЩҶ"
        count = f"{len(teams)}/32"
    else:
        title = "рҹҡӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ© Щ…ЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШӯШӘЩү Ш§Щ„ШўЩҶ"
        count = str(len(teams))
    lines = [title, f"Ш§Щ„Ш№ШҜШҜ: {count}", f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {state.get('updated_at') or '-'}", f"Ш§Щ„Щ…ШөШҜШұ: {state.get('source') or 'ЩҠШҜЩҲЩҠ'}"]
    if state.get(f"{kind}_manual_added"):
        lines.append("Щ…Ш№ Ш§Ш№ШӘЩ…Ш§ШҜ/ШӘШ№ШҜЩҠЩ„Ш§ШӘ ШҘШҜШ§ШұШ© Ш§Щ„Щ…ШөЩҠЩҒ")
    return "\n".join(lines)


def _render_status_board(kind, teams):
    if kind == "qualified":
        return render_qualified32_board(teams)
    return render_eliminated_board(teams)


def render_eliminated_board(teams):
    ensure_generated_dir()
    width, height = 1080, 1350
    try:
        img, draw = _games_day_background(width, height)
    except Exception:
        img = Image.new("RGB", (width, height), "#071426")
        draw = ImageDraw.Draw(img, "RGBA")
    overlay = Image.new("RGBA", (width, height), (0, 0, 0, 0))
    od = ImageDraw.Draw(overlay)
    rounded_rect(od, (55, 55, width-55, height-55), radius=46, fill="#06152FCC", outline="#FFFFFF33", width=2)
    img = Image.alpha_composite(img.convert("RGBA"), overlay).convert("RGB")
    draw = ImageDraw.Draw(img, "RGBA")
    draw_text(draw, (width//2, 95), "MONDIAL AL MASEEF 2026", _v31_latin_font(34) if '_v31_latin_font' in globals() else get_font(34), fill="#FFFFFF", max_width=860)
    draw_text(draw, (width//2, 165), "ELIMINATED TEAMS", _v31_latin_font(62) if '_v31_latin_font' in globals() else get_font(58), fill="#FFFFFF", max_width=940)
    draw_text(draw, (width//2, 230), "Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ Щ…ЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", get_font(42), fill="#FBBF24", max_width=830)

    cols = 3
    card_w, card_h = 290, 128
    gap_x, gap_y = 36, 28
    start_x = (width - (cols*card_w + (cols-1)*gap_x)) // 2
    start_y = 310
    teams = _unique_teams(teams)
    if not teams:
        rounded_rect(draw, (130, 520, width-130, 675), radius=28, fill="#061633E6", outline="#FFFFFF44", width=2)
        draw_text(draw, (width//2, 598), "Щ„Щ… ЩҠШӘЩ… ШӘШіШ¬ЩҠЩ„ ШЈЩҠ Щ…ЩҶШӘШ®ШЁ Щ…ШәШ§ШҜШұ ШӯШӘЩү Ш§Щ„ШўЩҶ", get_font(34), fill="#FFFFFF", max_width=760)
    for idx, team in enumerate(teams[:24]):
        row = idx // cols
        col_from_right = idx % cols
        # ЩҶШ№ШЁЩ‘ЩҠ Щ…ЩҶ Ш§Щ„ЩҠЩ…ЩҠЩҶ Щ„Щ„ЩҠШіШ§Шұ
        col = cols - 1 - col_from_right
        x = start_x + col*(card_w+gap_x)
        y = start_y + row*(card_h+gap_y)
        rounded_rect(draw, (x, y, x+card_w, y+card_h), radius=24, fill="#111827E8", outline="#EF4444AA", width=2)
        try:
            paste_flag(img, team, (x+card_w-95, y+24, x+card_w-25, y+76))
        except Exception:
            pass
        draw_text(draw, (x+card_w-110, y+50), team, _fit_font_to_width(draw, team, 28, 165, min_size=18), fill="#FFFFFF", anchor="rm", max_width=165)
        draw_text(draw, (x+card_w-30, y+101), f"#{idx+1}", get_font(24), fill="#FBBF24", anchor="rm")
        draw_text(draw, (x+38, y+101), "ШәШ§ШҜШұ", get_font(22), fill="#FCA5A5")
    draw.line((250, height-120, width-250, height-120), fill="#FFFFFF77", width=2)
    draw_text(draw, (width//2, height-72), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(34), fill="#FBBF24", max_width=720)
    path = os.path.join(GENERATED_DIR, "eliminated_teams_board.png")
    img.save(path, quality=95)
    return path


def _parse_team_from_command(text, command_names):
    s = normalize_name(text or "")
    for cmd in command_names:
        if s.startswith(cmd):
            return normalize_name(s[len(cmd):])
    parts = s.split(maxsplit=1)
    return normalize_name(parts[1]) if len(parts) > 1 else ""


async def _status_add_command(update, context, kind):
    if kind == "qualified":
        raw = _parse_team_from_command(update.message.text, ["/Щ…ШӘШЈЩҮЩ„"])
        example = "/Щ…ШӘШЈЩҮЩ„ Ш§Щ„Щ…ЩғШіЩҠЩғ"
        limit = 32
    else:
        raw = _parse_team_from_command(update.message.text, ["/Щ…ШәШ§ШҜШұ"])
        example = "/Щ…ШәШ§ШҜШұ ЩҶЩҠЩҲШІЩҠЩ„ЩҶШҜШ§"
        limit = None
    if not raw:
        await update.message.reply_text(f"Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n{example}")
        return
    team = canonical_team_name(raw)
    if not team:
        await update.message.reply_text(unsupported_team_message(raw))
        return
    state = load_status_state()
    prefix = "qualified" if kind == "qualified" else "eliminated"
    manual = _unique_teams(state.get(f"{prefix}_manual_added", []), limit)
    removed = _unique_teams(state.get(f"{prefix}_manual_removed", []))
    if team in removed:
        removed = [x for x in removed if x != team]
    if team not in manual:
        if limit and len(_status_effective_teams(kind, state)) >= limit:
            await update.message.reply_text("Ш§Щ„ЩӮШ§ШҰЩ…Ш© Щ…ЩғШӘЩ…Щ„Ш© вң…")
            return
        manual.append(team)
    state[f"{prefix}_manual_added"] = manual
    state[f"{prefix}_manual_removed"] = removed
    state["updated_at"] = _now_riyadh_text()
    state["source"] = "ШӘШ№ШҜЩҠЩ„ ЩҠШҜЩҲЩҠ Щ…ЩҶ Ш§Щ„ШҘШҜШ§ШұШ© + ESPN Ш№ЩҶШҜ Ш§Щ„ШӘШӯШҜЩҠШ«"
    save_status_state(state)
    teams = _status_effective_teams(kind, state)
    path = _render_status_board(kind, teams)
    await send_photo_path(update, path, f"ШӘЩ…ШӘ ШҘШ¶Ш§ЩҒШ© {team} вң…\n\n" + _status_caption(kind, teams, state))


async def _status_remove_command(update, context, kind):
    if kind == "qualified":
        raw = _parse_team_from_command(update.message.text, ["/ШӯШ°ЩҒ_Щ…ШӘШЈЩҮЩ„"])
        example = "/ШӯШ°ЩҒ_Щ…ШӘШЈЩҮЩ„ Ш§Щ„Щ…ЩғШіЩҠЩғ"
    else:
        raw = _parse_team_from_command(update.message.text, ["/ШӯШ°ЩҒ_Щ…ШәШ§ШҜШұ"])
        example = "/ШӯШ°ЩҒ_Щ…ШәШ§ШҜШұ ЩҶЩҠЩҲШІЩҠЩ„ЩҶШҜШ§"
    if not raw:
        await update.message.reply_text(f"Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n{example}")
        return
    team = canonical_team_name(raw)
    if not team:
        await update.message.reply_text(unsupported_team_message(raw))
        return
    state = load_status_state()
    prefix = "qualified" if kind == "qualified" else "eliminated"
    state[f"{prefix}_manual_added"] = [x for x in _unique_teams(state.get(f"{prefix}_manual_added", [])) if x != team]
    removed = _unique_teams(state.get(f"{prefix}_manual_removed", []))
    if team not in removed:
        removed.append(team)
    state[f"{prefix}_manual_removed"] = removed
    state["updated_at"] = _now_riyadh_text()
    state["source"] = "ШӘШ№ШҜЩҠЩ„ ЩҠШҜЩҲЩҠ Щ…ЩҶ Ш§Щ„ШҘШҜШ§ШұШ© + ESPN Ш№ЩҶШҜ Ш§Щ„ШӘШӯШҜЩҠШ«"
    save_status_state(state)
    teams = _status_effective_teams(kind, state)
    path = _render_status_board(kind, teams)
    await send_photo_path(update, path, f"ШӘЩ… ШӯШ°ЩҒ {team} вң…\n\n" + _status_caption(kind, teams, state))


async def qualified_add_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await _status_add_command(update, context, "qualified")


async def qualified_remove_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await _status_remove_command(update, context, "qualified")


async def eliminated_add_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await _status_add_command(update, context, "eliminated")


async def eliminated_remove_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await _status_remove_command(update, context, "eliminated")


async def qualified_show_board_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    state = load_status_state()
    teams = _status_effective_teams("qualified", state)
    path = render_qualified32_board(teams)
    await send_photo_path(update, path, _status_caption("qualified", teams, state))


async def eliminated_show_board_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    state = load_status_state()
    teams = _status_effective_teams("eliminated", state)
    path = render_eliminated_board(teams)
    await send_photo_path(update, path, _status_caption("eliminated", teams, state))


async def eliminated_list_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    state = load_status_state()
    teams = _status_effective_teams("eliminated", state)
    lines = [_status_caption("eliminated", teams, state), ""]
    lines += [f"{i}. {t}" for i, t in enumerate(teams, start=1)] or ["Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…ШәШ§ШҜШұШ© Щ…ШіШ¬Щ„Ш© ШӯШӘЩү Ш§Щ„ШўЩҶ."]
    await update.message.reply_text("\n".join(lines))


async def qualified_list_or_add_many_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = parse_command_body_lines(update.message.text)
    # ШЁШҜЩҲЩҶ ШЈШіЩ…Ш§ШЎ: Ш№ШұШ¶ Ш№Ш§Щ… Щ„Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ. Щ…Ш№ ШЈШіЩ…Ш§ШЎ: ШҘШ¶Ш§ЩҒШ© Ш¬Щ…Ш§Ш№ЩҠШ© Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ·.
    if not body:
        state = load_status_state()
        teams = _status_effective_teams("qualified", state)
        lines = [_status_caption("qualified", teams, state), ""]
        lines += [f"{i}. {t}" for i, t in enumerate(teams, start=1)] or ["Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…ШӘШЈЩҮЩ„Ш© Щ…ШіШ¬Щ„Ш© ШӯШӘЩү Ш§Щ„ШўЩҶ."]
        await update.message.reply_text("\n".join(lines))
        return
    if not is_admin_user(update):
        await update.message.reply_text("ШҘШ¶Ш§ЩҒШ© Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return
    # ШҘШ¶Ш§ЩҒШ© Ш¬Щ…Ш§Ш№ЩҠШ© Щ…ШӘЩҲШ§ЩҒЩӮШ© Щ…Ш№ V29 Ш§Щ„ЩӮШҜЩҠЩ….
    state = load_status_state()
    names = []
    if len(body) == 1 and ("," in body[0] or "ШҢ" in body[0]):
        names = [normalize_name(x) for x in re.split(r"[,ШҢ]", body[0]) if normalize_name(x)]
    else:
        names = body
    added, invalid, skipped = [], [], []
    manual = _unique_teams(state.get("qualified_manual_added", []), 32)
    removed = _unique_teams(state.get("qualified_manual_removed", []))
    for raw in names:
        team = canonical_team_name(raw)
        if not team:
            invalid.append(raw)
            continue
        if team in removed:
            removed = [x for x in removed if x != team]
        if team in manual:
            skipped.append(team)
            continue
        if len(_unique_teams(manual + state.get("qualified_auto", []), 32)) >= 32:
            break
        manual.append(team)
        added.append(team)
    state["qualified_manual_added"] = manual
    state["qualified_manual_removed"] = removed
    state["updated_at"] = _now_riyadh_text()
    state["source"] = "ШҘШ¶Ш§ЩҒШ© Ш¬Щ…Ш§Ш№ЩҠШ© ЩҠШҜЩҲЩҠШ© Щ…ЩҶ Ш§Щ„ШҘШҜШ§ШұШ©"
    save_status_state(state)
    teams = _status_effective_teams("qualified", state)
    path = render_qualified32_board(teams)
    cap = [_status_caption("qualified", teams, state)]
    if added:
        cap.append("\nШӘЩ…ШӘ Ш§Щ„ШҘШ¶Ш§ЩҒШ©:\n- " + "\n- ".join(added))
    if skipped:
        cap.append("\nЩ…ЩҲШ¬ЩҲШҜ Щ…ШіШЁЩӮЩӢШ§:\n- " + "\n- ".join(skipped[:8]))
    if invalid:
        cap.append("\nШӘШ№Ш°Шұ Ш§Щ„ШӘШ№ШұЩҒ Ш№Щ„Щү:\n- " + "\n- ".join(invalid[:8]))
    await send_photo_path(update, path, "\n".join(cap))


def _status_row_to_values(row):
    try:
        team = row[0]
        played = int(row[1]) if len(row) > 1 else 0
        diff = int(row[2]) if len(row) > 2 else 0
        pts = int(row[3]) if len(row) > 3 else 0
        return team, played, diff, pts
    except Exception:
        return "", 0, 0, 0


def _auto_status_from_groups(groups):
    qualified, eliminated = [], []
    third_rows = []
    all_groups_complete = True
    for title, rows in groups or []:
        clean_rows = []
        for row in rows[:4]:
            team, played, diff, pts = _status_row_to_values(row)
            if team:
                clean_rows.append((team, played, diff, pts))
        if len(clean_rows) < 4:
            all_groups_complete = False
            continue
        group_complete = all(p >= 3 for _team, p, _diff, _pts in clean_rows)
        if not group_complete:
            all_groups_complete = False
            continue
        # ESPN ЩҠШ№Ш·ЩҠЩҶШ§ Ш§Щ„ШӘШұШӘЩҠШЁ Ш¬Ш§ЩҮШІ: Ш§Щ„ШЈЩҲЩ„ ЩҲШ§Щ„Ш«Ш§ЩҶЩҠ Щ…ШӘШЈЩҮЩ„Ш§ЩҶ ШұШіЩ…ЩҠЩӢШ§ ШЁШ№ШҜ ЩҶЩҮШ§ЩҠШ© Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.
        qualified.extend([clean_rows[0][0], clean_rows[1][0]])
        third_rows.append(clean_rows[2])
        eliminated.append(clean_rows[3][0])
    if all_groups_complete and len(third_rows) >= 12:
        # ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ„ШҜЩҲШұ 32ШҢ ЩҲШ§Щ„ШЁШ§ЩӮЩҠ ЩҠШәШ§ШҜШұ. ЩҶШіШӘШ®ШҜЩ… Ш§Щ„ЩҶЩӮШ§Ш· Ш«Щ… Ш§Щ„ЩҒШ§ШұЩӮ Ш«Щ… Ш§Щ„Ш§ШіЩ… ЩғШӘШұШӘЩҠШЁ Щ…ШӯШ§ЩҒШё.
        ranked_thirds = sorted(third_rows, key=lambda x: (x[3], x[2], x[0]), reverse=True)
        qualified.extend([x[0] for x in ranked_thirds[:8]])
        eliminated.extend([x[0] for x in ranked_thirds[8:]])
    return _unique_teams(qualified, 32), _unique_teams(eliminated)


