    try:
        groups, source_label = await asyncio.wait_for(asyncio.to_thread(fetch_current_groups, "espn"), timeout=40)
    except Exception as e:
        await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ ESPN вқҢ\n{str(e)[:250]}")
        return
    if not groups:
        await wait.edit_text("ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ESPN ШӯШ§Щ„ЩҠЩӢШ§.")
        return
    q_auto, e_auto = _auto_status_from_groups(groups)
    state = load_status_state()
    state["qualified_auto"] = q_auto
    state["eliminated_auto"] = e_auto
    state["updated_at"] = _now_riyadh_text()
    state["source"] = f"ESPN Standings вҖ” ШӘШӯШҜЩҠШ« ШӘЩ„ЩӮШ§ШҰЩҠ Щ…ШӯШ§ЩҒШё"
    save_status_state(state)
    q_eff = _status_effective_teams("qualified", state)
    e_eff = _status_effective_teams("eliminated", state)
    await wait.edit_text(
        "ШӘЩ… ШӘШӯШҜЩҠШ« Ш§Щ„ЩӮЩҲШ§ШҰЩ… вң…\n"
        f"Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ: {len(q_eff)}/32\n"
        f"Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ: {len(e_eff)}\n"
        "Щ…Щ„Ш§ШӯШёШ©: Ш§Щ„ЩҠШҜЩҲЩҠ Щ„ЩҮ ШЈЩҲЩ„ЩҲЩҠШ©ШҢ ЩҲШ§Щ„ШӘЩ„ЩӮШ§ШҰЩҠ Щ„Ш§ ЩҠШ№ШӘЩ…ШҜ ШҙЩҠШЎ ШәЩҠШұ ЩҲШ§Ш¶Шӯ ЩӮШЁЩ„ Ш§ЩғШӘЩ…Ш§Щ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©."
    )


