    if action == "results":
        prev = _v28_previous_result_dates() if '_v28_previous_result_dates' in globals() else []
        if not prev:
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… ШіШ§ШЁЩӮШ© Щ„Щ„ЩҶШӘШ§ШҰШ¬ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
