# 3) ЩҮШҜШ§ЩҒЩҲ Ш§Щ„ШЁШ·ЩҲЩ„Ш©: Ш¶ШЁШ· Ш§Щ„ЩҶШө ШҜШ§Ш®Щ„ Ш§Щ„Щ…ШұШЁШ№Ш§ШӘ ЩҲШЁШ§Щ„Ш№ШұШЁЩҠ
# 4) Ш§Щ„ЩҶШӘШ§ШҰШ¬/Ш§Щ„Щ…ШЁШ§ШҙШұ: ШӘЩҶШёЩҠЩҒ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ ЩҲЩ…ЩҶШ№ Ш§Щ„ЩҲШөЩҒ Ш§Щ„ШҘЩҶШ¬Щ„ЩҠШІЩҠ Ш§Щ„Ш·ЩҲЩҠЩ„
# 5) Ш§Щ„Щ…ШЁШ§ШҙШұ: Щ…ЩҶШ№ Ш§Щ„ШІШӯЩ…Ш© Ш№ЩҶШҜ ШӘШәЩҠЩҠШұ Ш§Щ„Щ…ШөШ§ШҜШұ (ШЁШҜЩҲЩҶ ШұШіШ§ШҰЩ„ Ш®Ш·ШЈ Щ…ШӘЩғШұШұШ©)
# 6) Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ/Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ: Щ„Ш§ ЩҶШӯШіШЁ Щ…ЩҶ Ш§Щ„ШӘШұШӘЩҠШЁШҢ ЩҶШЁШӯШ« ШЁШ§Щ„ШҘЩҶШ¬Щ„ЩҠШІЩҠ Ш№ЩҶ ШЈШ®ШЁШ§Шұ ШұШіЩ…ЩҠШ© ЩҒЩӮШ·ШҢ Щ…Ш№ ШҘШЁЩӮШ§ШЎ Ш§Щ„ЩҠШҜЩҲЩҠ ШЈЩҲЩ„ЩҲЩҠШ©.

import html as _html
import time as _time
from urllib.parse import quote_plus as _quote_plus


def _v31_strip_html(s):
    s = re.sub(r"<script.*?</script>", " ", str(s or ""), flags=re.I | re.S)
    s = re.sub(r"<style.*?</style>", " ", s, flags=re.I | re.S)
    s = re.sub(r"<[^>]+>", " ", s)
    s = _html.unescape(s)
    s = re.sub(r"\s+", " ", s)
    return s.strip()


def _v31_team_name_en(team):
    can = canonical_team_name(team) or normalize_name(team)
    if not can:
        return ""
    candidates = []
    for k, v in TEAM_ALIASES.items():
        if v == can and re.search(r"[A-Za-z]", str(k)):
            candidates.append(str(k))
    # ШӘШӯШіЩҠЩҶШ§ШӘ ЩҠШҜЩҲЩҠШ© Щ„ШЈШіЩ…Ш§ШЎ ЩҶШЁЩҠЩҮШ§ ШЁШҙЩғЩ„ ШҙШ§ШҰШ№ ЩҒЩҠ Ш§Щ„ШЁШӯШ«
    preferred = {
        "Ш§Щ„ЩҲЩ„Ш§ЩҠШ§ШӘ Ш§Щ„Щ…ШӘШӯШҜШ©": "United States",
        "ШіШ§ШӯЩ„ Ш§Щ„Ш№Ш§Ш¬": "Ivory Coast",
        "ШӘШұЩғЩҠШ§": "Turkey",
        "ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©": "South Korea",
        "Ш§Щ„ШӘШҙЩҠЩғ": "Czechia",
        "ЩҮЩҲЩ„ЩҶШҜШ§": "Netherlands",
        "Ш§Щ„ШҘЩғЩҲШ§ШҜЩҲШұ": "Ecuador",
        "ЩғЩҲШұШ§ШіШ§ЩҲ": "Curacao",
    }
    if can in preferred:
        return preferred[can]
    if candidates:
        # ЩҶЩҒШ¶Щ‘Щ„ Ш§Щ„Ш§ШіЩ… Ш§Щ„ШЈШ·ЩҲЩ„ ЩӮЩ„ЩҠЩ„ЩӢШ§ ШҘШ°Ш§ ЩғШ§ЩҶ Ш§Ш®ШӘШөШ§ШұЩӢШ§ Щ…Ш«Щ„ USA
        candidates = sorted(set(candidates), key=lambda x: (len(x) < 4, len(x)))
        return candidates[0]
    return can


def _v31_team_same(a, b):
    ca = canonical_team_name(a) or normalize_name(a)
    cb = canonical_team_name(b) or normalize_name(b)
    if ca == cb:
        return True
    ea = _v31_team_name_en(ca).lower()
    eb = _v31_team_name_en(cb).lower()
    if ea and eb and (ea == eb or ea in eb or eb in ea):
        return True
    try:
        sa = simple_key(ca)
        sb = simple_key(cb)
        return sa == sb or sa in sb or sb in sa
    except Exception:
        return False


# ЩҶШ№ЩҠШҜ Ш§Щ„ШӘШ№ШұЩҠЩҒ Щ„ШӘШӯШіЩҠЩҶ Щ…Ш·Ш§ШЁЩӮШ© ШЈШіЩ…Ш§ШЎ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…Ш№ ESPN Щ…Ш«Щ„ ШіШ§ШӯЩ„ Ш§Щ„Ш№Ш§Ш¬ / CГҙte d'Ivoire.
def _v28_team_same(a, b):
    return _v31_team_same(a, b)


def _v31_goal_line_from_text(raw):
    s = normalize_name(raw or "")
    s = s.replace("вҖ“", "-").replace("вҖ”", "-").replace("вҖў", " ")
    s = re.sub(r"\s+", " ", s).strip(" -вҖ“вҖ”:|ШҢ")
    if not s:
        return ""

    bad_phrases = [
        "left footed shot", "right footed shot", "very close range", "close range",
        "centre of the", "center of the", "dutch fans celebrate", "the number of",
        "shots that are on", "shots on", "hurting to be sat", "match report",
        "team stats", "player stats", "commentary", "full commentary", "full time",
        "halftime", "substitution", "yellow card", "red card", "offside", "penalty missed",
        "interception", "possession", "foul by", "assisted by", "own goal by", "video highlights"
    ]
    low = s.lower()
    if any(p in low for p in bad_phrases):
        return ""

    # ЩҶШӯШ§ЩҲЩ„ Ш§ШіШӘШ®ШұШ§Ш¬ Ш§ШіЩ… + ШҜЩӮЩҠЩӮШ©/ШҜЩӮШ§ШҰЩӮ ЩҒЩӮШ·.
    # ШЈЩ…Ш«Щ„Ш©:
    # Brian Brobbey - 5'
    # Brian Brobbey 5'
    # Brian Brobbey - 5', 17'
    minute_part = ""
    mm = re.findall(r"(\d{1,3}(?:\+\d{1,2})?)\s*['вҖҷ]", s)
    if mm:
        minute_part = "ШҢ ".join([f"{x}'" for x in mm])
    name = s
    # ШҘШІШ§Щ„Ш© ШЈЩҠ Ш¬ШІШЎ ШЁШ№ШҜ Ш§Щ„ШҙШұШ·Ш© ШҘШ°Ш§ ЩғШ§ЩҶ ЩҲШөЩҒЩӢШ§
    if " - " in name:
        left, right = name.split(" - ", 1)
        if re.search(r"\d", right):
            name = left.strip()
    name = re.sub(r"\b(goal|scores|scored|penalty goal|own goal)\b.*$", "", name, flags=re.I).strip(" -вҖ“вҖ”:|ШҢ")
    name = re.sub(r"\s+", " ", name)

    # ШҘШ°Ш§ Щ…Ш§ ШЁЩӮЩҠ ШҘЩ„Ш§ ЩҲШөЩҒ ШЈЩҲ Ш§Щ„Ш¬Щ…Щ„Ш© Ш·ЩҲЩҠЩ„Ш© Ш¬ШҜЩӢШ§ ЩҶШұЩҒШ¶ЩҮШ§
    if len(name) < 2 or len(name) > 45:
        return ""
    # ШЈШіЩ…Ш§ШЎ ШөШӯЩҠШӯШ© ШәШ§Щ„ШЁЩӢШ§ ШӘЩғЩҲЩҶ 1-4 ЩғЩ„Щ…Ш§ШӘШҢ Ш§Щ„Ш№ШұШЁЩҠ ЩӮШҜ ЩҠШөЩ„ 5
    if len(name.split()) > 5:
        return ""
    # ШҘШ°Ш§ ЩҠЩҲШ¬ШҜ ЩҶЩӮШ·ШӘШ§ЩҶ/ШұЩҲШ§ШЁШ·/ЩҲШөЩҒ Ш·ЩҲЩҠЩ„ ЩҶШұЩҒШ¶
    if any(tok in name for tok in ["http://", "https://", "/soccer/", "ESPN", "FIFA World Cup"]):
        return ""

    # ШӘШұШ¬Щ…Ш© Ш§ШіЩ… Ш§Щ„Щ„Ш§Ш№ШЁ ШҘШ°Ш§ ЩҲШ¬ШҜ
    name_ar = _player_name_ar(name) if '_player_name_ar' in globals() else name
    name_ar = name_ar or name
    if minute_part:
        return f"{name_ar} вҡҪпёҸ {minute_part}"
    return name_ar


def _v31_prepare_scorers(items):
    out = []
    for item in items or []:
        line = _v31_goal_line_from_text(item)
        if not line:
            continue
        if line not in out:
            out.append(line)
    return out[:10]


# ШҘШ№Ш§ШҜШ© ШӘШ№ШұЩҠЩҒ ШӘЩҶШёЩҠЩҒ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ ШЁШҙЩғЩ„ Щ…ШӯШ§ЩҒШё Ш¬ШҜЩӢШ§.
def _v28_sanitize_scorers(items):
    return _v31_prepare_scorers(items)


def _v31_match_scorers(match):
    scorers = _v31_prepare_scorers(match.get("scorers") or [])
    return scorers[:8]


# ШӘШЁШіЩҠШ· ЩғШ§ШЁШҙЩҶ Ш§Щ„Щ…ШЁШ§ШҙШұ Щ„Щ…ЩҶШ№ Ш§Щ„ШұЩҲШ§ШЁШ· ЩҲШ§Щ„ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„ШІШ§ШҰШҜШ©.
def build_live_caption(match, mode_label="ШұШіЩ…ЩҠ"):
    t1 = canonical_team_name(match.get("team1")) or normalize_name(match.get("team1") or "")
    t2 = canonical_team_name(match.get("team2")) or normalize_name(match.get("team2") or "")
    s1 = str(match.get("score1", "-"))
    s2 = str(match.get("score2", "-"))
    status = normalize_name(match.get("status") or match.get("minute") or "")
    lines = [f"{t1} {s1} - {s2} {t2}"]
    if status:
        lines.append(status)
    scorers = _v31_match_scorers(match)
    if scorers:
        lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ:")
        lines += [f"- {x}" for x in scorers]
    else:
        lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ: ШәЩҠШұ Щ…ШӘЩҲЩҒШұЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
    src = normalize_name(match.get("actual_source") or match.get("source") or mode_label or "ESPN")
    lines.append("")
    lines.append(f"Ш§Щ„Щ…ШөШҜШұ: {src}")
    return "\n".join(lines).strip()


def _v31_result_text_for_date(date):
    d = _normalize_date_arg(date)
    matches = _v26_dedupe_fixture_matches(_fixtures_for_date(d)) if '_v26_dedupe_fixture_matches' in globals() else _fixtures_for_date(d)
    if not matches:
        return f"Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ ШЁШӘШ§ШұЩҠШ® {d}"

    title = _v26_fixture_title(d) if '_v26_fixture_title' in globals() else d
    lines = [f"рҹҸҶ ЩҶШӘШ§ШҰШ¬ Щ…ШЁШ§ШұЩҠШ§ШӘ {title} рҹҸҶ", "Ш§Щ„Щ…ШөШҜШұ: ESPN", ""]

    for i, m in enumerate(matches, start=1):
        obj = None
        try:
            obj = _v28_fetch_espn_match_by_fixture(d, m)
        except Exception:
            obj = None
        if obj:
            t1 = canonical_team_name(m.get('team1')) or normalize_name(m.get('team1') or '')
            t2 = canonical_team_name(m.get('team2')) or normalize_name(m.get('team2') or '')
            lines.append(f"{i}) {t1} {obj.get('score1','-')} - {obj.get('score2','-')} {t2}")
            scorers = _v31_match_scorers(obj)
            if scorers:
                lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ:")
                for s in scorers[:8]:
                    lines.append(f"- {s}")
            else:
                lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ: ШәЩҠШұ Щ…ШӘЩҲЩҒШұЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
        else:
            lines.append(f"{i}) {m.get('team1')} Г— {m.get('team2')} вҖ” Щ„Щ… ШӘШӘЩҲЩҒШұ Ш§Щ„ЩҶШӘЩҠШ¬Ш© ШЁШ№ШҜ")
            lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ: ШәЩҠШұ Щ…ШӘЩҲЩҒШұЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
        lines.append("")

    return "\n".join(lines).strip()


# ШҘШ№Ш§ШҜШ© ШӘШ№ШұЩҠЩҒ ШЈШІШұШ§Шұ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Ш§Щ„Ш№Ш§Щ…Ш©.
def _v28_previous_results_keyboard():
    rows, row = [], []
    for d, day in _v28_previous_result_dates():
        row.append(InlineKeyboardButton(f"{day} {d[:5]}", callback_data=f"res|day|{d}"))
        if len(row) == 2:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№ Щ„Щ„ЩӮШ§ШҰЩ…Ш©", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    if len(parts) >= 3 and parts[1] == "day":
        d = parts[2]
        wait = await q.message.reply_text("вҸі ШЈШіШӯШЁ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШ§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN...")
        try:
            text = await asyncio.wait_for(asyncio.to_thread(_v31_result_text_for_date, d), timeout=35)
            await wait.edit_text(text)
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҶШӘШ§ШҰШ¬ ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ… вқҢ\n{str(e)[:400]}")
        return


