async def public_status_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    kind = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "qualified"
    state = load_status_state()
    # Щ„Ш§ ЩҶШ№ШӘЩ…ШҜ Ш№Щ„Щү Ш§Щ„ШӯШіШ§ШЁ Щ…ЩҶ Ш§Щ„ШӘШұШӘЩҠШЁШӣ ЩҶШӯШҜШ« Щ…ЩҶ Ш§Щ„ШЈШ®ШЁШ§Шұ Ш§Щ„ШұШіЩ…ЩҠШ© ЩҒЩӮШ·.
    if _v31_state_needs_refresh(state) or not state.get("qualified_auto") and kind == "qualified" or not state.get("eliminated_auto") and kind == "eliminated":
        try:
            state = await asyncio.wait_for(asyncio.to_thread(_v31_refresh_status_from_news, state), timeout=80)
        except Exception:
            state = load_status_state()
    if kind == "qualified":
        teams = _status_effective_teams("qualified", state)
        path = render_qualified32_board(teams)
        await send_photo_path(q.message, path, _status_caption("qualified", teams, state))
    elif kind == "eliminated":
        teams = _status_effective_teams("eliminated", state)
        path = render_eliminated_board(teams)
        await send_photo_path(q.message, path, _status_caption("eliminated", teams, state))
    else:
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")


async def groups_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    action = parts[1] if len(parts) > 1 else ""

    if action in {"all", "half1", "half2"}:
        wait = await q.message.reply_text("вҸі ШЈШіШӯШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ESPN...")
        try:
            groups, source_label = await asyncio.wait_for(asyncio.to_thread(fetch_current_groups, "espn"), timeout=35)
            if not groups:
                await wait.edit_text("ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ESPN ШӯШ§Щ„ЩҠЩӢШ§.")
                return
            try:
                await wait.delete()
            except Exception:
                pass
            if action == "half1":
                path = create_all_groups_newlook_image(groups[:6], title_ar="6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", title_en="GROUP STANDINGS", filename_hint="groups_half1_v31")
                await send_photo_path(q.message, path, "ШӘШұШӘЩҠШЁ 6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN")
                return
            if action == "half2":
                path = create_all_groups_newlook_image(groups[6:12], title_ar="6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", title_en="GROUP STANDINGS", filename_hint="groups_half2_v31")
                await send_photo_path(q.message, path, "ШӘШұШӘЩҠШЁ 6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN")
                return
            path1 = create_all_groups_newlook_image(groups[:6], title_ar="6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", title_en="GROUP STANDINGS", filename_hint="groups_all_page1_v31")
            path2 = create_all_groups_newlook_image(groups[6:12], title_ar="6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", title_en="GROUP STANDINGS", filename_hint="groups_all_page2_v31")
            await send_photo_path(q.message, path1, "ШӘШұШӘЩҠШЁ Ш¬Щ…ЩҠШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ вң… (1/2)\nШ§Щ„Щ…ШөШҜШұ: ESPN")
            await send_photo_path(q.message, path2, "ШӘШұШӘЩҠШЁ Ш¬Щ…ЩҠШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ вң… (2/2)\nШ§Щ„Щ…ШөШҜШұ: ESPN")
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„ШӘШұШӘЩҠШЁ вқҢ\n{str(e)[:300]}")
        return

    if action == "one" and len(parts) >= 3:
        code = parts[2]
        wait = await q.message.reply_text(f"вҸі ШЈШіШӯШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {code} Щ…ЩҶ ESPN...")
        try:
            groups, source_label = await asyncio.wait_for(asyncio.to_thread(fetch_current_groups, "espn"), timeout=35)
            title, rows = _v29_find_group(groups, code)
            if not rows:
                await wait.edit_text("ШӘШ№Ш°Шұ Ш§Щ„Ш№Ш«ЩҲШұ Ш№Щ„Щү ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШӯШ§Щ„ЩҠЩӢШ§.")
                return
            path = _v29_render_single_group_image(title, rows)
            await send_photo_path(q.message, path, f"{title} вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN")
            try:
                await wait.delete()
            except Exception:
                pass
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© вқҢ\n{str(e)[:300]}")
        return


# ШӘЩӮЩ„ЩҠЩ„ Ш§Щ„ШІШӯЩ…Ш©: Ш№ЩҶШҜ ШӘШәЩҠЩҠШұ Ш§Щ„Щ…ШөШҜШұ Щ„Ш§ ЩҶШұШіЩ„ ШұШіШ§ШҰЩ„ Ш®Ш·ШЈ ЩғШ«ЩҠШұШ©Шӣ ЩҶШіШӘШ®ШҜЩ… ШӘЩҶШЁЩҠЩҮ ЩҒЩӮШ· Ш№ЩҶШҜ Ш§Щ„ЩҒШҙЩ„.
async def sports_source_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return
    try:
        await query.answer("вҸі Ш¬Ш§ШұЩҠ Ш§Щ„Щ…ШӯШ§ЩҲЩ„Ш©...")
    except Exception:
        try:
            await query.answer()
        except Exception:
            pass
    parts = (query.data or "").split("|")
    if len(parts) != 3:
        await query.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
        return
    _tag, token, mode = parts
    payload = context.bot_data.get("sports_source_requests", {}).get(token)
    if not payload:
        await query.message.reply_text("Ш§ЩҶШӘЩҮШӘ ШөЩ„Ш§ШӯЩҠШ© Ш§Щ„Ш®ЩҠШ§ШұШҢ ШЈШ№ШҜ ШӘЩҶЩҒЩҠШ° Ш§Щ„ШЈЩ…Шұ Щ…ЩҶ Ш¬ШҜЩҠШҜ.")
        return
    kind = payload.get("kind")
    kb = source_keyboard(context, payload)

    if kind == "standings":
        try:
            groups, src = await asyncio.wait_for(asyncio.to_thread(fetch_current_groups, mode), timeout=32)
        except Exception:
            groups, src = [], ""
        if not groups:
            try:
                await query.answer(f"ШӘШ№Ш°Шұ Ш§Щ„Ш¬Щ„ШЁ Щ…ЩҶ {mode_label_ar(mode)}", show_alert=True)
            except Exception:
                pass
            return
        path1 = create_all_groups_newlook_image(groups[:6], title_ar="6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", title_en="GROUP STANDINGS", filename_hint="src_groups1_v31")
        path2 = create_all_groups_newlook_image(groups[6:12], title_ar="6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", title_en="GROUP STANDINGS", filename_hint="src_groups2_v31")
        await send_photo_path_markup(query.message, path1, f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң… (1/2)\nШ§Щ„Щ…ШөШҜШұ: {src}", kb)
        await send_photo_path(query.message, path2, f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң… (2/2)\nШ§Щ„Щ…ШөШҜШұ: {src}")
        return

    if kind == "live":
        team1 = payload.get("team1")
        team2 = payload.get("team2")
        date_hint = payload.get("date_hint")
        try:
            data = await asyncio.wait_for(asyncio.to_thread(fetch_live_match_data, team1, team2, mode, date_hint), timeout=26)
        except Exception:
            data = None
        if not data:
            fixture = None
            try:
                dd = _normalize_date_arg(date_hint) if date_hint else _v29_active_fixture_date()
                for mm in _fixtures_for_date(dd) or []:
                    if _v31_team_same(mm.get("team1"), team1) and _v31_team_same(mm.get("team2"), team2):
                        fixture = mm
                        break
            except Exception:
                fixture = None
            if fixture:
                try:
                    path, caption = _v29_render_fixture_fallback_card(fixture, mode_label_ar(mode))
                    await send_photo_path_markup(query.message, path, caption, kb)
                    return
                except Exception:
                    pass
            try:
                await query.answer(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ {mode_label_ar(mode)}", show_alert=True)
            except Exception:
                pass
            return
        path = render_live_match_card(data, mode_label_ar(mode))
        await send_photo_path_markup(query.message, path, build_live_caption(data, mode_label_ar(mode)), kb)
        return
    await query.message.reply_text("ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШҜ ЩҶЩҲШ№ Ш§Щ„Ш·Щ„ШЁ.")


# Status picker callback-data ШўЩ…ЩҶ: Ш§Щ„ШЈШІШұШ§Шұ ШӘШ№ШұШ¶ ШЈШіЩ…Ш§ШЎ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ„ЩғЩҶ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ ШӘШіШӘШ®ШҜЩ… ШұЩӮЩ… Ш§Щ„Щ…ЩҶШӘШ®ШЁ.
def _status_picker_keyboard(kind="qualified", selected=None):
    selected = set(_unique_teams(selected or []))
    rows, row = [], []
    for idx, team in enumerate(WORLD_CUP_TEAMS):
        mark = "вң… " if team in selected else ""
        row.append(InlineKeyboardButton(mark + team, callback_data=f"spick|toggle|{kind}|{idx}"))
        if len(row) == 3:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    rows.append([InlineKeyboardButton("вң… ШӘШЈЩғЩҠШҜ", callback_data=f"spick|confirm|{kind}"), InlineKeyboardButton("ШӘШөЩҒЩҠШұ", callback_data=f"spick|clear|{kind}")])
    rows.append([InlineKeyboardButton("ШҘЩ„ШәШ§ШЎ", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


async def status_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    if not is_admin_user(update):
        await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return
    parts = (q.data or "").split("|")
    action = parts[1] if len(parts) > 1 else ""
    kind = parts[2] if len(parts) > 2 else "qualified"
    key = f"spick_{kind}"
    selected = _unique_teams(context.user_data.get(key) or [])
    if action == "toggle" and len(parts) >= 4:
        try:
            team = WORLD_CUP_TEAMS[int(parts[3])]
        except Exception:
            team = canonical_team_name(parts[3]) or normalize_name(parts[3])
        if team in selected:
            selected = [x for x in selected if x != team]
        else:
            selected.append(team)
        context.user_data[key] = selected
        title = "Ш§Ш®ШӘШұ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„Щ…ШӘШЈЩҮЩ„Ш© Щ…ШЁШ§ШҙШұШ© Ш«Щ… Ш§Ш¶ШәШ· ШӘШЈЩғЩҠШҜ:" if kind == "qualified" else "Ш§Ш®ШӘШұ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„Щ…ШіШӘШЁШ№ШҜШ© Щ…ШЁШ§ШҙШұШ© Ш«Щ… Ш§Ш¶ШәШ· ШӘШЈЩғЩҠШҜ:"
        await q.edit_message_text(title, reply_markup=_status_picker_keyboard(kind, selected))
        return
    if action == "clear":
        context.user_data[key] = []
        await q.edit_message_text("ШӘЩ… ШӘШөЩҒЩҠШұ Ш§Щ„Ш§Ш®ШӘЩҠШ§Шұ. Ш§Ш®ШӘШұ Щ…ЩҶ Ш¬ШҜЩҠШҜ:", reply_markup=_status_picker_keyboard(kind, []))
        return
    if action == "confirm":
        state = load_status_state()
        prefix = "qualified" if kind == "qualified" else "eliminated"
        current = _unique_teams(state.get(f"{prefix}_manual_added", []), 32 if prefix == "qualified" else None)
        for team in selected:
            if team not in current:
                current.append(team)
        state[f"{prefix}_manual_added"] = _unique_teams(current, 32 if prefix == "qualified" else None)
        other = "eliminated" if prefix == "qualified" else "qualified"
        state[f"{other}_manual_added"] = [x for x in _unique_teams(state.get(f"{other}_manual_added", [])) if x not in selected]
        state[f"{other}_auto"] = [x for x in _unique_teams(state.get(f"{other}_auto", [])) if x not in selected]
        state["updated_at"] = _now_riyadh_text()
        state["source"] = "Ш§Ш®ШӘЩҠШ§Шұ ЩҠШҜЩҲЩҠ Щ…ЩҶ Ш§Щ„ШҘШҜШ§ШұШ© ШЁШ§Щ„ШЈШІШұШ§Шұ"
        save_status_state(state)
        teams = _status_effective_teams(kind, state)
        context.user_data[key] = []
        msg = "ШӘЩ… Ш§Ш№ШӘЩ…Ш§ШҜ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ вң…" if kind == "qualified" else "ШӘЩ… Ш§Ш№ШӘЩ…Ш§ШҜ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҠЩҶ/Ш§Щ„Щ…ШәШ§ШҜШұЩҠЩҶ вң…"
        await q.edit_message_text(f"{msg}\nШ§Щ„Ш№ШҜШҜ Ш§Щ„ШӯШ§Щ„ЩҠ: {len(teams)}")
        path = render_qualified32_board(teams) if kind == "qualified" else render_eliminated_board(teams)
        await send_photo_path(q.message, path, _status_caption(kind, teams, state))
        return


# ==================== END V31 FINAL PATCH ====================



