    if txt == "рҹ“Ҡ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ":
        await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЈЩҲ 6 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШЈЩҲ Ш¬Щ…ЩҠШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ:", reply_markup=_v29_group_menu_keyboard())
