# ЩҒЩ„ШӘШұ ШЈЩҮШҜШ§ЩҒ ЩҶЩҮШ§ШҰЩҠ: ЩҠЩ„ШӘЩӮШ· ШўШ®Шұ Ш§ШіЩ… Щ„Ш§Ш№ШЁ ЩӮШЁЩ„ Ш§Щ„ШҜЩӮЩҠЩӮШ© ЩҒЩӮШ·ШҢ ЩҲЩ„Ш§ ЩҠШ№ШұШ¶ Ш§Щ„ЩҲШөЩҒ Ш§Щ„Ш·ЩҲЩҠЩ„.
def _clean_strict_scorer_line(s):
    s = normalize_name(s)
    s = re.sub(r"\s+", " ", s).strip(" -вҖ“вҖ”:вҖў|ШҢ")
    if not s:
        return ""
    minutes = list(_minute_regex().finditer(s))
    if not minutes:
        return ""

    names = []
    mins = []
    for mn in minutes:
        minute = mn.group(1) + "'"
        prefix = s[:mn.start()].strip()
        # ЩӮШө ШўШ®Шұ Ш¬Щ…Щ„Ш© ЩҒЩӮШ·Шӣ ЩҠШӯШ°ЩҒ assisted/corner/cross ЩҲШ§Щ„ЩҲШөЩҒ Ш§Щ„ШіШ§ШЁЩӮ.
        for sep in [".", "Шӣ", ";", "\n"]:
            if sep in prefix:
                prefix = prefix.split(sep)[-1].strip()
        # Щ„ЩҲ ЩҒЩҠЩҮ ШҙШұШ·Ш© ЩӮШЁЩ„ Ш§Щ„ШҜЩӮЩҠЩӮШ©ШҢ Ш®Ш° ШўШ®Шұ Ш¬ШІШЎ ШәЩҠШұ ЩҒШ§ШұШә ЩӮШЁЩ„ Ш§Щ„ШҜЩӮЩҠЩӮШ©.
        # Щ…Ш«Ш§Щ„: "RaГәl JimГ©nez вҖ” 67'" => "RaГәl JimГ©nez"
        # ЩҲЩ…Ш«Ш§Щ„: "Goal - RaГәl JimГ©nez 67'" => "RaГәl JimГ©nez"
        if "вҖ”" in prefix or "вҖ“" in prefix or "-" in prefix:
            parts = [x.strip() for x in re.split(r"[-вҖ“вҖ”]", prefix) if x.strip()]
            if parts:
                prefix = parts[-1]
        # ШӯШ°ЩҒ Ш№ШЁШ§ШұШ§ШӘ ЩҲШөЩҒЩҠШ© ЩӮШЁЩ„ Ш§Щ„Ш§ШіЩ… ШЁШҜЩҲЩҶ ШұЩ…ЩҠ Ш§Щ„Ш§ШіЩ… ЩҶЩҒШіЩҮ.
        prefix = re.sub(r"(?i)\b(super substitute|substitute|volley|header|goal|penalty goal|own goal|scores|scored|assisted by|with a cross|from a corner|corner)\b", " ", prefix)
        prefix = re.sub(r"(?i)\b(from|inside|outside|bottom|top|right|left|centre|center|box|shot|cross)\b.*", " ", prefix)
        prefix = re.sub(r"\s+", " ", prefix).strip(" -вҖ“вҖ”:вҖў|ШҢ")

        # Щ…ЩҶ Ш§Щ„ШЁШ§ЩӮЩҠ Ш®Ш° ШўШ®Шұ 1-4 ЩғЩ„Щ…Ш§ШӘ ЩҒЩҠЩҮШ§ ШӯШұЩҲЩҒШҢ Щ„ШЈЩҶ Ш§ШіЩ… Ш§Щ„Щ„Ш§Ш№ШЁ ШәШ§Щ„ШЁЩӢШ§ ШўШ®Шұ ШҙЩҠШЎ ЩӮШЁЩ„ Ш§Щ„ШҜЩӮЩҠЩӮШ©.
        tokens = [t.strip(" ,ШҢШӣ:()[]{}") for t in prefix.split() if re.search(r"[A-Za-zГҖ-Г–Гҳ-Г¶Гё-ГҝШЎ-ЩҠ]", t)]
        if not tokens:
            continue
        cand = " ".join(tokens[-4:])
        # Щ„ЩҲ cand Ш·ЩҲЩҠЩ„ Ш¬ШҜЩӢШ§ШҢ Ш®Ш° ШўШ®Шұ 3 ЩғЩ„Щ…Ш§ШӘ.
        if len(cand) > 38 and len(tokens) >= 3:
            cand = " ".join(tokens[-3:])
        bad_exact = {"volley", "header", "highlights", "highlight", "goal", "report", "recap"}
        if cand.lower() in bad_exact or len(cand) < 2:
            continue
        if _BAD_SCORER_TEXT.search(cand) and not re.search(r"[ШЎ-ЩҠ]", cand):
            continue
        if cand not in names:
            names.append(cand)
        mins.append((cand, minute))

    by = {}
    for name, minute in mins:
        by.setdefault(name, [])
        if minute not in by[name]:
            by[name].append(minute)
    lines = []
    for name, arr in by.items():
        lines.append(f"{name} вҖ” {'ШҢ '.join(arr)}")
    return lines[0] if len(lines) == 1 else " | ".join(lines[:3])


def _v28_sanitize_scorers(items):
    out = []
    for item in items or []:
        cleaned = _clean_strict_scorer_line(item)
        # ШҘШ°Ш§ Ш®ШұШ¬ ШЈЩғШ«Шұ Щ…ЩҶ Щ„Ш§Ш№ШЁ Щ…ЩҒШөЩҲЩ„ ШЁШ№Щ„Ш§Щ…Ш© | ЩҶЩҒШөЩ„ЩҮЩ….
        parts = [x.strip() for x in str(cleaned or "").split("|")]
        for line in parts:
            if line and line not in out:
                out.append(line)
    return out[:10]


# ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…Ш№ Cache: ШЈЩҲЩ„ Щ…ШұШ© ЩҠШіШӯШЁШҢ ШЁШ№ШҜЩҮШ§ ЩҠШ№ШұШ¶ ЩҒЩҲШұЩӢШ§.
def _load_results_cache():
    return _json_load_file(MATCH_RESULTS_CACHE_FILE, {})


def _save_results_cache(data):
    _json_save_file(MATCH_RESULTS_CACHE_FILE, data)


_v315_uncached_result_text_for_date = _v28_result_text_for_date

def _v28_result_text_for_date(date, force_refresh=False):
    d = _normalize_date_arg(date)
    cache = _load_results_cache()
    if (not force_refresh) and cache.get(d):
        return cache[d].get("text") or ""
    txt = _v315_uncached_result_text_for_date(d)
    if txt and not txt.startswith("Щ…Ш§ Щ„ЩӮЩҠШӘ") and "ШӘШ№Ш°Шұ" not in txt:
        cache[d] = {"text": txt, "updated_at": _now_riyadh_text()}
        _save_results_cache(cache)
    return txt


async def refresh_results_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    dates = _extract_fixture_dates_from_text(update.message.text)
    if not dates:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШӘШӯШҜЩҠШ«_ЩҶШӘШ§ШҰШ¬ 11/06")
        return
    d = dates[0]
    wait = await update.message.reply_text(f"вҸі ШЈШӯШҜШ« ЩҶШӘШ§ШҰШ¬ {d} Щ…ЩҶ Ш§Щ„Щ…ШөШҜШұ...")
    try:
        txt = await asyncio.wait_for(asyncio.to_thread(_v28_result_text_for_date, d, True), timeout=45)
        await wait.edit_text(txt)
    except Exception as e:
        await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШ« Ш§Щ„ЩҶШӘШ§ШҰШ¬ вқҢ\n{str(e)[:300]}")


def _status_picker_keyboard(kind="qualified", selected=None):
    # ЩғЩ„ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…ШЁШ§ШҙШұШ©ШҢ ШЁШҜЩҲЩҶ Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.
    selected = set(_unique_teams(selected or []))
    rows, row = [], []
    for team in WORLD_CUP_TEAMS:
        mark = "вң… " if team in selected else ""
        row.append(InlineKeyboardButton(mark + team, callback_data=f"spick|toggle|{kind}|{team}"))
        if len(row) == 3:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    rows.append([InlineKeyboardButton("вң… ШӘШЈЩғЩҠШҜ", callback_data=f"spick|confirm|{kind}"), InlineKeyboardButton("ШӘШөЩҒЩҠШұ", callback_data=f"spick|clear|{kind}")])
    rows.append([InlineKeyboardButton("ШҘЩ„ШәШ§ШЎ", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


