    if action == "highlights":
        if not any((v or {}).get("url") for v in _load_highlights().values()):
            await q.edit_message_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„Ш®ШөШ§ШӘ Щ…Ш¶Ш§ЩҒШ© ШӯШ§Щ„ЩҠЩӢШ§.")
