    if action == "scorers":
        wait = await q.message.reply_text("вҸі ШЈШіШӯШЁ ЩҮШҜШ§ЩҒЩҠ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN...")
        try:
            items = await asyncio.wait_for(asyncio.to_thread(fetch_espn_top_scorers), timeout=35)
            path = render_top_scorers_v29(items)
            try: await wait.delete()
            except Exception: pass
            await send_photo_path(q.message, path, "ЩҮШҜШ§ЩҒЩҲ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN")
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҮШҜШ§ЩҒЩҠ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вқҢ\n{str(e)[:300]}")
        return
    if action == "help":
        await q.edit_message_text(_public_help_text())
        return


