# ---------- FIFA: Ш§Щ„Щ…ШҙШұЩҒ ЩҠШӯШҜШ« ЩҒЩӮШ·ШҢ Щ…Ш№ ШіШЁШЁ ЩҒШҙЩ„ ШЈЩҲШ¶Шӯ ----------

def _fifa_status_from_html_with_reason():
    if not requests:
        return [], [], "Щ…ЩғШӘШЁШ© requests ШәЩҠШұ Щ…ШӘЩҲЩҒШұШ©"
    try:
        r = _requests_get(FIFA_STATUS_URL, headers={"User-Agent": "Mozilla/5.0"}, timeout=22) if 'headers' in getattr(_requests_get, '__code__', type('x',(),{'co_varnames':()})()).co_varnames else _requests_get(FIFA_STATUS_URL, timeout=22)
        status = int(getattr(r, 'status_code', 200) or 200)
        if status >= 400:
            return [], [], f"FIFA ШұШ¬Ш№ ЩғЩҲШҜ HTTP {status}"
        html = getattr(r, 'text', '') or ''
        if len(html) < 300:
            return [], [], "ШөЩҒШӯШ© FIFA ШұШ¬Ш№ШӘ Щ…ШӯШӘЩҲЩү ЩӮШөЩҠШұ/ЩҒШ§ШұШә"
    except Exception as e:
        return [], [], f"ШӘШ№Ш°Шұ Ш§Щ„Ш§ШӘШөШ§Щ„ ШЁШөЩҒШӯШ© FIFA: {str(e)[:120]}"
    try:
        q, e = _fifa_status_from_html()
    except Exception as ex:
        return [], [], f"ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© ШөЩҒШӯШ© FIFA: {str(ex)[:120]}"
    if not q and not e:
        return [], [], "ШөЩҒШӯШ© FIFA Щ„Щ… ШӘШұШ¬Ш№ Ш¬ШҜЩҲЩ„ ЩӮШ§ШЁЩ„ Щ„Щ„ЩӮШұШ§ШЎШ©Шӣ ШәШ§Щ„ШЁЩӢШ§ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ ШҜЩҠЩҶШ§Щ…ЩҠЩғЩҠШ©"
    return q, e, ""


async def _v315_refresh_fifa_and_send(msg, kind="qualified"):
    wait = await msg.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ ЩҲШ§Щ„Щ…ШәШ§ШҜШұЩҠЩҶ Щ…ЩҶ FIFA Ш§Щ„ШұШіЩ…ЩҠ...")
    old_state = load_status_state()
    try:
        q_auto, e_auto, reason = await asyncio.wait_for(asyncio.to_thread(_fifa_status_from_html_with_reason), timeout=55)
    except Exception:
        q_auto, e_auto, reason = [], [], "Ш§ЩҶШӘЩҮШӘ Щ…ЩҮЩ„Ш© Ш§Щ„Ш§ШӘШөШ§Щ„ ШЁЩҖ FIFA"
    if not q_auto and not e_auto:
        await wait.edit_text(f"вҡ пёҸ ШӘШ№Ш°Шұ Ш§Щ„ШӘШӯШҜЩҠШ« Щ…ЩҶ FIFA ШӯШ§Щ„ЩҠЩӢШ§\nШ§Щ„ШіШЁШЁ: {reason}\nШЁЩӮЩҠШӘ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШіШ§ШЁЩӮШ© Щ…ШӯЩҒЩҲШёШ© ЩғЩ…Ш§ ЩҮЩҠ.")
        return
    state = old_state
    state['qualified_auto'] = _unique_teams(q_auto, 32)
    state['eliminated_auto'] = _unique_teams(e_auto)
    state['updated_at'] = _now_riyadh_text()
    state['updated_ts'] = _time.time() if '_time' in globals() else 0
    state['source'] = 'FIFA Ш§Щ„ШұШіЩ…ЩҠ + ШӘШӯШҜЩҠШ« Ш§Щ„Щ…ШҙШұЩҒ'
    save_status_state(state)
    teams = _status_effective_teams(kind, state)
    path = render_qualified32_board(teams) if kind == 'qualified' else render_eliminated_board(teams)
    try:
        await wait.delete()
    except Exception:
        pass
    await send_photo_path_markup(msg, path, _status_caption(kind, teams, state), _status_admin_keyboard(kind))

