    if not rows:
        rows.append([InlineKeyboardButton("Щ„Ш§ ШӘЩҲШ¬ШҜ ШЈЩҠШ§Щ… ЩҶШӘШ§ШҰШ¬ ШӯШӘЩү Ш§Щ„ШўЩҶ", callback_data="noop")])
    rows.append([InlineKeyboardButton("ШҘЩ„ШәШ§ШЎ", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


